def concept_direction_angle_layer_evolution(all_acts, concept_names):
    """Phase 503: How pairwise concept angles evolve across layers."""
    print("=" * 70)
    print("PHASE 503: Pairwise Concept Angle Evolution Across Layers")
    print("=" * 70)
    num_layers = len(all_acts[concept_names[0]]["positive"])
    # Pick the most correlated pair: sentiment vs emotion_joy_anger
    c1, c2 = "sentiment", "emotion_joy_anger"
    if c1 in concept_names and c2 in concept_names:
        angles = []
        for l in range(num_layers):
            d1 = all_acts[c1]["positive"][l].mean(0) - all_acts[c1]["negative"][l].mean(0)
            d2 = all_acts[c2]["positive"][l].mean(0) - all_acts[c2]["negative"][l].mean(0)
            cos = np.dot(d1, d2) / (np.linalg.norm(d1) * np.linalg.norm(d2) + 1e-10)
            angles.append(np.degrees(np.arccos(np.clip(cos, -1, 1))))
        min_l = int(np.argmin(angles))
        max_l = int(np.argmax(angles))
        print(f"  {c1} vs {c2}:")
        print(f"    Min angle: {angles[min_l]:.1f}° at L{min_l}")
        print(f"    Max angle: {angles[max_l]:.1f}° at L{max_l}")
        print(f"    L0: {angles[0]:.1f}°  L10: {angles[10]:.1f}°  L23: {angles[23]:.1f}°")
    print()


def concept_activation_sparse_coding(all_acts, concept_names):
    """Phase 504: Sparse coding of concept activations via OMP."""
    print("=" * 70)
    print("PHASE 504: Sparse Coding of Concept Activations")
    print("=" * 70)
    layer = 10
    all_data = []
    for cname in concept_names:
        all_data.append(all_acts[cname]["positive"][layer])
        all_data.append(all_acts[cname]["negative"][layer])
    all_data = np.vstack(all_data)
    # Use SVD as dictionary
    U, S, Vt = np.linalg.svd(all_data - all_data.mean(0), full_matrices=False)
    dict_atoms = Vt[:20]  # top 20 atoms
    for cname in concept_names:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        d = pos.mean(0) - neg.mean(0)
        coeffs = dict_atoms @ d
        sorted_idx = np.argsort(np.abs(coeffs))[::-1]
        top3 = sorted_idx[:3]
        recon = dict_atoms[top3].T @ coeffs[top3]
        recon_err = np.linalg.norm(d - recon) / (np.linalg.norm(d) + 1e-10)
        print(f"  {cname:20s} top 3 atoms reconstruct {(1-recon_err)*100:.1f}% of direction")
    print()


def concept_neuron_activation_temporal_pattern(all_acts, concept_names, sparse_results):
    """Phase 505: Check if top neuron activations show sample-order patterns."""
    print("=" * 70)
    print("PHASE 505: Neuron Activation Sample-Order Patterns")
    print("=" * 70)
    for cname in concept_names:
        sr = sparse_results.get(cname, {})
        best_layer = sr.get("best_layer", 10)
        top_ns = sr.get("top_neurons", [0, 1, 2])[:1]
        pos = all_acts[cname]["positive"][best_layer]
        for n in top_ns:
            vals = pos[:, n]
            # Autocorrelation at lag 1
            if len(vals) > 2:
                mean_v = vals.mean()
                var_v = vals.var()
                if var_v > 0:
                    autocorr = np.mean((vals[:-1] - mean_v) * (vals[1:] - mean_v)) / var_v
                else:
                    autocorr = 0
            else:
                autocorr = 0
            print(f"  {cname:20s} N{n:3d}: lag-1 autocorr={autocorr:.4f}")
    print()


def concept_direction_effective_dimensionality(all_acts, concept_names):
    """Phase 506: Effective dimensionality of the concept direction subspace."""
    print("=" * 70)
    print("PHASE 506: Concept Direction Subspace Effective Dimensionality")
    print("=" * 70)
    layer = 10
    dirs = []
    for cname in concept_names:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        d = pos.mean(0) - neg.mean(0)
        dirs.append(d)
    D = np.array(dirs)
    U, S, Vt = np.linalg.svd(D, full_matrices=False)
    S_norm = S / S.sum()
    eff_dim = np.exp(-np.sum(S_norm * np.log(S_norm + 1e-10)))
    cum_var = np.cumsum(S**2) / np.sum(S**2)
    n95 = int(np.searchsorted(cum_var, 0.95)) + 1
    print(f"  Effective dimensionality of concept subspace: {eff_dim:.2f}")
    print(f"  Dims for 95% variance: {n95}")
    print(f"  Singular values: {', '.join(f'{s:.2f}' for s in S)}")
    print()


def concept_activation_between_within_ratio(all_acts, concept_names):
    """Phase 507: Between-class / within-class variance ratio (multivariate)."""
    print("=" * 70)
    print("PHASE 507: Between/Within Class Variance Ratio (Multivariate)")
    print("=" * 70)
    layer = 10
    for cname in concept_names:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        grand_mean = np.concatenate([pos, neg], axis=0).mean(0)
        n_p, n_n = len(pos), len(neg)
        between = n_p * np.outer(pos.mean(0) - grand_mean, pos.mean(0) - grand_mean) + \
                  n_n * np.outer(neg.mean(0) - grand_mean, neg.mean(0) - grand_mean)
        within = (pos - pos.mean(0)).T @ (pos - pos.mean(0)) + \
                 (neg - neg.mean(0)).T @ (neg - neg.mean(0))
        # Use trace ratio as simple scalar
        bw_ratio = np.trace(between) / (np.trace(within) + 1e-10)
        print(f"  {cname:20s} trace(B)/trace(W) = {bw_ratio:.4f}")
    print()


def concept_neuron_sparsity_gini(all_acts, concept_names):
    """Phase 508: Gini coefficient of neuron importance for each concept."""
    print("=" * 70)
    print("PHASE 508: Neuron Importance Gini Coefficient")
    print("=" * 70)
    layer = 10
    for cname in concept_names:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        d = pos.mean(0) - neg.mean(0)
        importance = np.abs(d)
        importance = np.sort(importance)
        n = len(importance)
        idx = np.arange(1, n + 1)
        gini = (2 * np.sum(idx * importance) / (n * np.sum(importance)) - (n + 1) / n) if np.sum(importance) > 0 else 0
        print(f"  {cname:20s} Gini coefficient: {gini:.4f}")
    print()


def concept_direction_pairwise_projection(all_acts, concept_names):
    """Phase 509: Projection of each concept's data onto other concept directions."""
    print("=" * 70)
    print("PHASE 509: Cross-Concept Projection Analysis")
    print("=" * 70)
    layer = 10
    dirs = {}
    for cname in concept_names:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        d = pos.mean(0) - neg.mean(0)
        dirs[cname] = d / (np.linalg.norm(d) + 1e-10)
    # Show how much concept A data projects onto concept B direction
    for c1 in concept_names[:4]:
        pos = all_acts[c1]["positive"][layer]
        neg = all_acts[c1]["negative"][layer]
        data = np.vstack([pos, neg])
        projections = {}
        for c2 in concept_names[:4]:
            if c2 == c1:
                continue
            proj_var = np.var(data @ dirs[c2])
            projections[c2] = proj_var
        parts = [f"{c2}:{v:.2f}" for c2, v in projections.items()]
        print(f"  {c1:15s} proj variance onto: " + " | ".join(parts))
    print()


def concept_activation_layer_transition_smoothness(all_acts, concept_names):
    """Phase 510: Smoothness of concept direction transitions between layers."""
    print("=" * 70)
    print("PHASE 510: Layer Transition Smoothness")
    print("=" * 70)
    num_layers = len(all_acts[concept_names[0]]["positive"])
    for cname in concept_names:
        cosines = []
        for l in range(num_layers - 1):
            d1 = all_acts[cname]["positive"][l].mean(0) - all_acts[cname]["negative"][l].mean(0)
            d2 = all_acts[cname]["positive"][l+1].mean(0) - all_acts[cname]["negative"][l+1].mean(0)
            cos = np.dot(d1, d2) / (np.linalg.norm(d1) * np.linalg.norm(d2) + 1e-10)
            cosines.append(cos)
        smoothness = np.mean(cosines)
        roughest = int(np.argmin(cosines))
        print(f"  {cname:20s} mean smoothness: {smoothness:.4f}, roughest: L{roughest}->L{roughest+1} ({cosines[roughest]:.4f})")
    print()


def concept_direction_leave_one_out_stability(all_acts, concept_names):
    """Phase 511: Leave-one-concept-out effect on remaining directions."""
    print("=" * 70)
    print("PHASE 511: Leave-One-Concept-Out Direction Stability")
    print("=" * 70)
    layer = 10
    dirs = {}
    for cname in concept_names:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        d = pos.mean(0) - neg.mean(0)
        dirs[cname] = d / (np.linalg.norm(d) + 1e-10)
    # Full Gram matrix
    full_G = np.array([[np.dot(dirs[c1], dirs[c2]) for c2 in concept_names] for c1 in concept_names])
    full_cond = np.linalg.cond(full_G)
    for drop in concept_names:
        remaining = [c for c in concept_names if c != drop]
        sub_G = np.array([[np.dot(dirs[c1], dirs[c2]) for c2 in remaining] for c1 in remaining])
        sub_cond = np.linalg.cond(sub_G)
        delta = full_cond - sub_cond
        print(f"  Drop {drop:20s}: cond={sub_cond:.2f} (delta={delta:+.2f})")
    print()


def concept_neuron_firing_rate_balance(all_acts, concept_names, sparse_results):
    """Phase 512: How balanced are neuron firing rates across concepts."""
    print("=" * 70)
    print("PHASE 512: Neuron Firing Rate Balance Across Concepts")
    print("=" * 70)
    layer = 10
    # For each of top 10 neurons (by max importance), check how evenly they fire across concepts
    all_importance = np.zeros(all_acts[concept_names[0]]["positive"][layer].shape[1])
    for cname in concept_names:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        d = np.abs(pos.mean(0) - neg.mean(0))
        all_importance += d
    top10 = np.argsort(all_importance)[-10:][::-1]
    for n in top10[:5]:
        rates = []
        for cname in concept_names:
            pos = all_acts[cname]["positive"][layer]
            neg = all_acts[cname]["negative"][layer]
            mean_act = np.abs(np.concatenate([pos[:, n], neg[:, n]])).mean()
            rates.append(mean_act)
        rates = np.array(rates)
        cv = rates.std() / (rates.mean() + 1e-10)
        print(f"  N{n:3d}: mean_rate={rates.mean():.3f} CV={cv:.4f} (low CV = balanced)")
    print()


def concept_activation_distance_ratio(all_acts, concept_names):
    """Phase 513: Ratio of inter-class to intra-class distances."""
    print("=" * 70)
    print("PHASE 513: Inter/Intra Class Distance Ratio")
    print("=" * 70)
    layer = 10
    for cname in concept_names:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        # Intra-class: mean pairwise distance within each class
        intra_p = np.mean(np.linalg.norm(pos[:, None] - pos[None, :], axis=2)[np.triu_indices(len(pos), k=1)])
        intra_n = np.mean(np.linalg.norm(neg[:, None] - neg[None, :], axis=2)[np.triu_indices(len(neg), k=1)])
        intra = (intra_p + intra_n) / 2
        # Inter-class: distance between centroids
        inter = np.linalg.norm(pos.mean(0) - neg.mean(0))
        ratio = inter / (intra + 1e-10)
        print(f"  {cname:20s} inter/intra ratio: {ratio:.4f}")
    print()


def concept_direction_projection_kurtosis(all_acts, concept_names):
    """Phase 514: Kurtosis of projections onto concept directions (non-Gaussianity)."""
    print("=" * 70)
    print("PHASE 514: Projection Kurtosis (Non-Gaussianity)")
    print("=" * 70)
    from scipy.stats import kurtosis as sp_kurtosis
    layer = 10
    for cname in concept_names:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        d = pos.mean(0) - neg.mean(0)
        d = d / (np.linalg.norm(d) + 1e-10)
        all_data = np.vstack([pos, neg])
        projs = all_data @ d
        k = sp_kurtosis(projs, fisher=True)
        print(f"  {cname:20s} projection kurtosis: {k:.4f} {'(platykurtic)' if k < 0 else '(leptokurtic)'}")
    print()


def concept_neuron_concept_specificity_entropy(all_acts, concept_names):
    """Phase 515: For each neuron, entropy of its importance distribution across concepts."""
    print("=" * 70)
    print("PHASE 515: Neuron Concept-Specificity Entropy")
    print("=" * 70)
    layer = 10
    hidden = all_acts[concept_names[0]]["positive"][layer].shape[1]
    importance_matrix = np.zeros((len(concept_names), hidden))
    for i, cname in enumerate(concept_names):
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        importance_matrix[i] = np.abs(pos.mean(0) - neg.mean(0))
    # Normalize per neuron
    col_sums = importance_matrix.sum(axis=0) + 1e-10
    normed = importance_matrix / col_sums
    entropies = -np.sum(normed * np.log2(normed + 1e-10), axis=0)
    max_ent = np.log2(len(concept_names))
    mean_ent = entropies.mean()
    n_specialist = (entropies < max_ent * 0.5).sum()
    n_generalist = (entropies > max_ent * 0.8).sum()
    print(f"  Max possible entropy: {max_ent:.3f} bits")
    print(f"  Mean neuron entropy:  {mean_ent:.3f} bits")
    print(f"  Specialists (<50% max): {n_specialist}/{hidden}")
    print(f"  Generalists (>80% max): {n_generalist}/{hidden}")
    print()


def concept_activation_silhouette_score(all_acts, concept_names):
    """Phase 516: Silhouette score treating concepts as clusters."""
    print("=" * 70)
    print("PHASE 516: Concept Silhouette Score")
    print("=" * 70)
    layer = 10
    all_data = []
    labels = []
    for i, cname in enumerate(concept_names):
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        all_data.append(np.vstack([pos, neg]))
        labels.extend([i] * (len(pos) + len(neg)))
    all_data = np.vstack(all_data)
    labels = np.array(labels)
    # Compute simplified silhouette on centroids
    centroids = np.array([all_data[labels == i].mean(0) for i in range(len(concept_names))])
    scores = []
    for idx in range(len(all_data)):
        own = labels[idx]
        a = np.linalg.norm(all_data[idx] - centroids[own])
        b = min(np.linalg.norm(all_data[idx] - centroids[j]) for j in range(len(concept_names)) if j != own)
        s = (b - a) / (max(a, b) + 1e-10)
        scores.append(s)
    mean_sil = np.mean(scores)
    per_concept = {concept_names[i]: np.mean([scores[j] for j in range(len(labels)) if labels[j] == i]) for i in range(len(concept_names))}
    print(f"  Overall silhouette: {mean_sil:.4f}")
    for cname in concept_names:
        print(f"    {cname:20s}: {per_concept[cname]:.4f}")
    print()


def concept_direction_cosine_distribution(all_acts, concept_names):
    """Phase 517: Full distribution of pairwise cosines between concept directions."""
    print("=" * 70)
    print("PHASE 517: Pairwise Concept Direction Cosine Distribution")
    print("=" * 70)
    layer = 10
    dirs = []
    for cname in concept_names:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        d = pos.mean(0) - neg.mean(0)
        d = d / (np.linalg.norm(d) + 1e-10)
        dirs.append(d)
    cosines = []
    for i in range(len(dirs)):
        for j in range(i+1, len(dirs)):
            cosines.append(np.dot(dirs[i], dirs[j]))
    cosines = np.array(cosines)
    print(f"  N pairs: {len(cosines)}")
    print(f"  Mean cosine: {cosines.mean():.6f}")
    print(f"  Std cosine:  {cosines.std():.6f}")
    print(f"  Max |cosine|: {np.max(np.abs(cosines)):.6f}")
    print(f"  Min |cosine|: {np.min(np.abs(cosines)):.6f}")
    # Count near-orthogonal pairs
    n_orth = (np.abs(cosines) < 0.1).sum()
    print(f"  Near-orthogonal (|cos|<0.1): {n_orth}/{len(cosines)}")
    print()


