def concept_activation_explained_variance_by_direction(all_acts, concept_names):
    """Phase 519: How much total variance is explained by each concept direction."""
    print("=" * 70)
    print("PHASE 519: Variance Explained by Each Concept Direction")
    print("=" * 70)
    layer = 10
    # Pool all data
    all_data = []
    for cname in concept_names:
        all_data.append(all_acts[cname]["positive"][layer])
        all_data.append(all_acts[cname]["negative"][layer])
    all_data = np.vstack(all_data)
    total_var = np.var(all_data, axis=0).sum()
    for cname in concept_names:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        d = pos.mean(0) - neg.mean(0)
        d = d / (np.linalg.norm(d) + 1e-10)
        proj = all_data @ d
        explained = np.var(proj)
        frac = explained / (total_var + 1e-10)
        print(f"  {cname:20s} explained variance: {frac*100:.2f}%")
    # Total
    dirs = []
    for cname in concept_names:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        d = pos.mean(0) - neg.mean(0)
        d = d / (np.linalg.norm(d) + 1e-10)
        dirs.append(d)
    D = np.array(dirs)
    proj_all = all_data @ D.T
    total_explained = np.sum(np.var(proj_all, axis=0))
    print(f"  Total by all 8 directions: {total_explained/total_var*100:.2f}%")
    print()


def concept_direction_gram_schmidt_residual_norms(all_acts, concept_names):
    """Phase 520: Gram-Schmidt residual norms show how much each direction is novel."""
    print("=" * 70)
    print("PHASE 520: Gram-Schmidt Residual Norms (Direction Novelty)")
    print("=" * 70)
    layer = 10
    dirs = []
    for cname in concept_names:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        d = pos.mean(0) - neg.mean(0)
        dirs.append(d)
    ortho_basis = []
    for i, (cname, d) in enumerate(zip(concept_names, dirs)):
        orig_norm = np.linalg.norm(d)
        residual = d.copy()
        for b in ortho_basis:
            residual -= np.dot(residual, b) * b
        res_norm = np.linalg.norm(residual)
        novelty = res_norm / (orig_norm + 1e-10)
        if res_norm > 1e-10:
            ortho_basis.append(residual / res_norm)
        print(f"  {cname:20s} novelty (residual/orig): {novelty:.4f}")
    print()


def concept_activation_centroid_distance_matrix(all_acts, concept_names):
    """Phase 521: Distance matrix between all concept centroids (pos+neg pooled)."""
    print("=" * 70)
    print("PHASE 521: Concept Centroid Distance Matrix")
    print("=" * 70)
    layer = 10
    centroids = []
    for cname in concept_names:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        centroids.append(np.vstack([pos, neg]).mean(0))
    centroids = np.array(centroids)
    dists = np.zeros((len(concept_names), len(concept_names)))
    for i in range(len(concept_names)):
        for j in range(len(concept_names)):
            dists[i, j] = np.linalg.norm(centroids[i] - centroids[j])
    # Show closest and farthest pairs
    tri_idx = np.triu_indices(len(concept_names), k=1)
    tri_dists = dists[tri_idx]
    closest = np.argmin(tri_dists)
    farthest = np.argmax(tri_dists)
    ci, cj = tri_idx[0][closest], tri_idx[1][closest]
    fi, fj = tri_idx[0][farthest], tri_idx[1][farthest]
    print(f"  Closest pair:  {concept_names[ci]:15s} - {concept_names[cj]:15s}: {tri_dists[closest]:.3f}")
    print(f"  Farthest pair: {concept_names[fi]:15s} - {concept_names[fj]:15s}: {tri_dists[farthest]:.3f}")
    print(f"  Mean distance: {tri_dists.mean():.3f}")
    print()


