        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        for label, data in [("pos", pos), ("neg", neg)]:
            norms = np.linalg.norm(data, axis=1, keepdims=True) + 1e-10
