        norm_p = np.linalg.norm(pos, axis=1).mean()
        norm_n = np.linalg.norm(neg, axis=1).mean()
        ratio = norm_p / (norm_n + 1e-10)
        print(f"  {cname:20s} | norm_pos={norm_p:.4f} | norm_neg={norm_n:.4f} | ratio={ratio:.4f}")
