    print(header)
    for i, cname in enumerate(concept_names):
        row = f"  {short_names[i]:10s}"
        for j in range(len(concept_names)):
            if i == j:
                row += f"{'---':>8s} "
            else:
                angle = np.degrees(np.arccos(np.clip(abs(cos_mat[i, j]), 0, 1)))
                row += f"{angle:7.1f}° "
        print(row)
    print()


