    combined = np.vstack(all_data)
    svd_vals = np.linalg.svd(combined - combined.mean(0), compute_uv=False)
    svd_vals = svd_vals[svd_vals > 1e-10]
    eff_dim = (svd_vals.sum()**2) / ((svd_vals**2).sum())
