    all_data = []
    all_labels = np.zeros((0, len(concept_names)))
    for idx, cname in enumerate(concept_names):
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        all_data.append(pos)
