def concept_activation_gradient_magnitude(all_acts, concept_names):
    """Phase 1154: Measure gradient magnitude of concept signal across layers."""
    print("=" * 70)
    print("PHASE 1154: CONCEPT SIGNAL GRADIENT ACROSS LAYERS")
    print("=" * 70)
    for cname in concept_names[:4]:
        norms = []
        for l in range(24):
            d = all_acts[cname]["positive"][l].mean(0) - all_acts[cname]["negative"][l].mean(0)
            norms.append(np.linalg.norm(d))
        gradients = np.diff(norms)
        max_grad_layer = int(np.argmax(np.abs(gradients)))
        print(f"  {cname:20s} | max gradient: {gradients[max_grad_layer]:+.3f} at L{max_grad_layer}->{max_grad_layer+1} | mean |grad|: {np.mean(np.abs(gradients)):.3f}")
    print()


def concept_within_class_compactness(all_acts, concept_names):
    """Phase 1155: Measure within-class compactness vs between-class separation."""
    print("=" * 70)
    print("PHASE 1155: WITHIN-CLASS COMPACTNESS")
    print("=" * 70)
    layer = 10
    for cname in concept_names:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        pos_compact = np.mean(np.linalg.norm(pos - pos.mean(0), axis=1))
        neg_compact = np.mean(np.linalg.norm(neg - neg.mean(0), axis=1))
        separation = np.linalg.norm(pos.mean(0) - neg.mean(0))
        ratio = separation / (pos_compact + neg_compact + 1e-10)
        print(f"  {cname:20s} | pos_compact: {pos_compact:.3f} | neg_compact: {neg_compact:.3f} | separation: {separation:.3f} | ratio: {ratio:.3f}")
    print()


def concept_direction_higher_order_alignment(all_acts, concept_names):
    """Phase 1156: Check alignment between concept directions and higher-order PCA components."""
    print("=" * 70)
    print("PHASE 1156: DIRECTION vs HIGHER-ORDER PCA ALIGNMENT")
    print("=" * 70)
    layer = 10
    for cname in concept_names[:4]:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        combined = np.vstack([pos, neg])
        combined_centered = combined - combined.mean(0)
        cov = np.cov(combined_centered.T)
        eigvals, eigvecs = np.linalg.eigh(cov)
        eigvecs = eigvecs[:, ::-1]  # descending
        direction = pos.mean(0) - neg.mean(0)
        direction = direction / (np.linalg.norm(direction) + 1e-10)
        alignments = [abs(float(direction @ eigvecs[:, i])) for i in range(5)]
        print(f"  {cname:20s} | PC alignment: " + " ".join(f"PC{i}={a:.3f}" for i, a in enumerate(alignments)))
    print()


def concept_neuron_selectivity_ratio_index(all_acts, concept_names):
    """Phase 1157: Compute selectivity index for each neuron across all concepts."""
    print("=" * 70)
    print("PHASE 1157: NEURON SELECTIVITY RATIO INDEX")
    print("=" * 70)
    layer = 10
    # For each neuron, compute how selective it is (max concept response / sum)
    n_neurons = all_acts[concept_names[0]]["positive"][layer].shape[1]
    selectivities = np.zeros(n_neurons)
    for j in range(n_neurons):
        responses = []
        for cname in concept_names:
            pos_mean = all_acts[cname]["positive"][layer][:, j].mean()
            neg_mean = all_acts[cname]["negative"][layer][:, j].mean()
            responses.append(abs(pos_mean - neg_mean))
        responses = np.array(responses)
        total = responses.sum() + 1e-10
        selectivities[j] = responses.max() / total
    top_selective = np.argsort(selectivities)[-10:][::-1]
    print(f"  Mean selectivity: {selectivities.mean():.4f}")
    print(f"  Top 10 most selective neurons:")
    for n in top_selective:
        print(f"    Neuron {n}: selectivity={selectivities[n]:.4f}")
    print()


def concept_activation_temporal_autocorrelation(all_acts, concept_names):
    """Phase 1158: Autocorrelation of concept signal strength across layers."""
    print("=" * 70)
    print("PHASE 1158: CONCEPT SIGNAL LAYER AUTOCORRELATION")
    print("=" * 70)
    for cname in concept_names[:4]:
        norms = []
        for l in range(24):
            d = all_acts[cname]["positive"][l].mean(0) - all_acts[cname]["negative"][l].mean(0)
            norms.append(np.linalg.norm(d))
        norms = np.array(norms)
        norms_centered = norms - norms.mean()
        var = np.var(norms)
        if var > 1e-10:
            autocorr_1 = np.mean(norms_centered[:-1] * norms_centered[1:]) / var
            autocorr_2 = np.mean(norms_centered[:-2] * norms_centered[2:]) / var
        else:
            autocorr_1 = autocorr_2 = 0.0
        print(f"  {cname:20s} | lag-1 autocorr: {autocorr_1:.4f} | lag-2 autocorr: {autocorr_2:.4f}")
    print()


def concept_concept_conditional_independence_test(all_acts, concept_names):
    """Phase 1159: Test conditional independence between concept pairs given a third concept."""
    print("=" * 70)
    print("PHASE 1159: CONDITIONAL INDEPENDENCE TEST")
    print("=" * 70)
    layer = 10
    # Pick 3 concept triplets
    triplets = [(0, 1, 2), (3, 4, 5), (0, 3, 6)]
    for i, j, k in triplets:
        c1, c2, c3 = concept_names[i], concept_names[j], concept_names[k]
        d1 = all_acts[c1]["positive"][layer].mean(0) - all_acts[c1]["negative"][layer].mean(0)
        d2 = all_acts[c2]["positive"][layer].mean(0) - all_acts[c2]["negative"][layer].mean(0)
        d3 = all_acts[c3]["positive"][layer].mean(0) - all_acts[c3]["negative"][layer].mean(0)
        d1 = d1 / (np.linalg.norm(d1) + 1e-10)
        d2 = d2 / (np.linalg.norm(d2) + 1e-10)
        d3 = d3 / (np.linalg.norm(d3) + 1e-10)
        # Partial correlation: corr(d1,d2) after removing d3
        d1_res = d1 - (d1 @ d3) * d3
        d2_res = d2 - (d2 @ d3) * d3
        d1_res = d1_res / (np.linalg.norm(d1_res) + 1e-10)
        d2_res = d2_res / (np.linalg.norm(d2_res) + 1e-10)
        partial_cos = float(d1_res @ d2_res)
        raw_cos = float(d1 @ d2)
        print(f"  {c1:12s} vs {c2:12s} | {c3:12s} | raw cos: {raw_cos:.4f} | partial cos: {partial_cos:.4f} | diff: {abs(raw_cos-partial_cos):.4f}")
    print()


def concept_direction_reconstruction_from_top_neurons(all_acts, concept_names):
    """Phase 1160: How well can we reconstruct concept direction from top-k neurons only."""
    print("=" * 70)
    print("PHASE 1160: DIRECTION RECONSTRUCTION FROM TOP-K NEURONS")
    print("=" * 70)
    layer = 10
    for cname in concept_names:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        direction = pos.mean(0) - neg.mean(0)
        norm = np.linalg.norm(direction)
        direction_unit = direction / (norm + 1e-10)
        importances = np.abs(direction)
        top_indices = np.argsort(importances)[::-1]
        for k in [1, 5, 10, 50]:
            sparse_dir = np.zeros_like(direction)
            sparse_dir[top_indices[:k]] = direction[top_indices[:k]]
            recon_cos = float(direction_unit @ sparse_dir / (np.linalg.norm(sparse_dir) + 1e-10))
            energy_pct = np.sum(sparse_dir ** 2) / (np.sum(direction ** 2) + 1e-10) * 100
            if cname == concept_names[0]:
                print(f"  {cname:20s} | k={k:3d}: cos={recon_cos:.4f}, energy={energy_pct:.1f}%")
        if cname != concept_names[0]:
            sparse_1 = np.zeros_like(direction)
            sparse_1[top_indices[:1]] = direction[top_indices[:1]]
            cos_1 = float(direction_unit @ sparse_1 / (np.linalg.norm(sparse_1) + 1e-10))
            sparse_50 = np.zeros_like(direction)
            sparse_50[top_indices[:50]] = direction[top_indices[:50]]
            cos_50 = float(direction_unit @ sparse_50 / (np.linalg.norm(sparse_50) + 1e-10))
            print(f"  {cname:20s} | k=1: cos={cos_1:.4f} | k=50: cos={cos_50:.4f}")
    print()


def concept_direction_subspace_overlap_analysis(all_acts, concept_names):
    """Phase 1161: Measure overlap between concept subspaces (top-k PCA dims)."""
    print("=" * 70)
    print("PHASE 1161: CONCEPT SUBSPACE OVERLAP ANALYSIS")
    print("=" * 70)
    layer = 10
    k = 5  # subspace dimension
    subspaces = {}
    for cname in concept_names:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        combined = np.vstack([pos, neg])
        centered = combined - combined.mean(0)
        cov = np.cov(centered.T)
        _, vecs = np.linalg.eigh(cov)
        subspaces[cname] = vecs[:, -k:]  # top-k eigenvectors
    pairs = [(concept_names[i], concept_names[j]) for i in range(len(concept_names)) for j in range(i+1, len(concept_names))]
    for c1, c2 in pairs[:6]:
        # Subspace overlap via principal angles
        M = subspaces[c1].T @ subspaces[c2]
        svals = np.linalg.svd(M, compute_uv=False)
        max_overlap = svals[0]
        mean_overlap = svals.mean()
        print(f"  {c1:12s} vs {c2:12s} | max overlap: {max_overlap:.4f} | mean overlap: {mean_overlap:.4f}")
    print()


def concept_neuron_firing_rate_distribution(all_acts, concept_names):
    """Phase 1162: Distribution of neuron firing rates across concepts."""
    print("=" * 70)
    print("PHASE 1162: NEURON FIRING RATE DISTRIBUTION")
    print("=" * 70)
    layer = 10
    for cname in concept_names[:4]:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        # "firing" = activation above mean
        combined = np.vstack([pos, neg])
        thresholds = combined.mean(0)
        pos_rates = (pos > thresholds).mean(0)
        neg_rates = (neg > thresholds).mean(0)
        rate_diff = np.abs(pos_rates - neg_rates)
        n_discriminative = (rate_diff > 0.3).sum()
        print(f"  {cname:20s} | discriminative neurons (>0.3 rate diff): {n_discriminative} | max rate diff: {rate_diff.max():.3f} | mean: {rate_diff.mean():.4f}")
    print()


def concept_direction_norm_layer_trajectory(all_acts, concept_names):
    """Phase 1163: Plot concept direction norm trajectory across all layers."""
    print("=" * 70)
    print("PHASE 1163: DIRECTION NORM LAYER TRAJECTORY")
    print("=" * 70)
    for cname in concept_names:
        norms = []
        for l in range(24):
            d = all_acts[cname]["positive"][l].mean(0) - all_acts[cname]["negative"][l].mean(0)
            norms.append(np.linalg.norm(d))
        peak = int(np.argmax(norms))
        trough = int(np.argmin(norms))
        print(f"  {cname:20s} | peak: L{peak} ({norms[peak]:.2f}) | trough: L{trough} ({norms[trough]:.2f}) | ratio: {norms[peak]/(norms[trough]+1e-10):.1f}x")
    print()


def concept_activation_mahalanobis_diagonal_separation(all_acts, concept_names):
    """Phase 1164: Mahalanobis distance between positive and negative concept clusters."""
    print("=" * 70)
    print("PHASE 1164: MAHALANOBIS DIAGONAL SEPARATION")
    print("=" * 70)
    layer = 10
    for cname in concept_names:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        combined = np.vstack([pos, neg])
        # Use diagonal covariance for efficiency
        var = np.var(combined, axis=0) + 1e-10
        diff = pos.mean(0) - neg.mean(0)
        mahal = np.sqrt(np.sum(diff ** 2 / var))
        euclid = np.linalg.norm(diff)
        print(f"  {cname:20s} | Mahalanobis: {mahal:.3f} | Euclidean: {euclid:.3f} | ratio: {mahal/(euclid+1e-10):.3f}")
    print()


def concept_neuron_correlation_network_density(all_acts, concept_names):
    """Phase 1165: Density of neuron correlation network per concept."""
    print("=" * 70)
    print("PHASE 1165: NEURON CORRELATION NETWORK DENSITY")
    print("=" * 70)
    layer = 10
    for cname in concept_names[:4]:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        combined = np.vstack([pos, neg])
        # Sample 100 neurons for efficiency
        rng = np.random.default_rng(42)
        idx = rng.choice(combined.shape[1], min(100, combined.shape[1]), replace=False)
        sub = combined[:, idx]
        corr = np.corrcoef(sub.T)
        np.fill_diagonal(corr, 0)
        density_05 = (np.abs(corr) > 0.5).sum() / (corr.size - len(corr))
        density_03 = (np.abs(corr) > 0.3).sum() / (corr.size - len(corr))
        print(f"  {cname:20s} | edges>0.5: {density_05:.4f} | edges>0.3: {density_03:.4f} | mean |corr|: {np.abs(corr).mean():.4f}")
    print()


def concept_direction_angle_to_random_baseline(all_acts, concept_names):
    """Phase 1166: Compare concept direction angles to random direction baselines."""
    print("=" * 70)
    print("PHASE 1166: DIRECTION ANGLES vs RANDOM BASELINE")
    print("=" * 70)
    layer = 10
    rng = np.random.default_rng(42)
    d = all_acts[concept_names[0]]["positive"][layer].shape[1]
    # Generate random directions
    random_dirs = rng.standard_normal((100, d))
    random_dirs = random_dirs / np.linalg.norm(random_dirs, axis=1, keepdims=True)
    # Mean pairwise angle among random directions
    random_cos = []
    for i in range(min(50, len(random_dirs))):
        for j in range(i+1, min(50, len(random_dirs))):
            random_cos.append(abs(float(random_dirs[i] @ random_dirs[j])))
    mean_random_angle = np.degrees(np.arccos(np.clip(np.mean(random_cos), 0, 1)))
    # Concept direction pairwise angles
    dirs = {}
    for cname in concept_names:
        dd = all_acts[cname]["positive"][layer].mean(0) - all_acts[cname]["negative"][layer].mean(0)
        dirs[cname] = dd / (np.linalg.norm(dd) + 1e-10)
    concept_cos = []
    for i in range(len(concept_names)):
        for j in range(i+1, len(concept_names)):
            concept_cos.append(abs(float(dirs[concept_names[i]] @ dirs[concept_names[j]])))
    mean_concept_angle = np.degrees(np.arccos(np.clip(np.mean(concept_cos), 0, 1)))
    print(f"  Mean concept pairwise angle: {mean_concept_angle:.1f}°")
    print(f"  Mean random pairwise angle:  {mean_random_angle:.1f}°")
    print(f"  Concepts are {'more' if mean_concept_angle > mean_random_angle else 'less'} orthogonal than random")
    print()


def concept_activation_sparsity_ratio(all_acts, concept_names):
    """Phase 1167: Measure activation sparsity (fraction near zero) per concept."""
    print("=" * 70)
    print("PHASE 1167: ACTIVATION SPARSITY RATIO")
    print("=" * 70)
    layer = 10
    for cname in concept_names:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        combined = np.vstack([pos, neg])
        threshold = 0.01 * np.abs(combined).max()
        sparse_frac = (np.abs(combined) < threshold).mean()
        l1_mean = np.abs(combined).mean()
        l2_mean = np.sqrt(np.mean(combined ** 2))
        print(f"  {cname:20s} | near-zero frac: {sparse_frac:.4f} | L1/L2: {l1_mean/(l2_mean+1e-10):.4f}")
    print()


def concept_direction_concept_direction_weighted_layer_ensemble(all_acts, concept_names):
    """Phase 1168: Ensemble concept directions across layers with signal-weighted averaging."""
    print("=" * 70)
    print("PHASE 1168: WEIGHTED LAYER ENSEMBLE DIRECTION")
    print("=" * 70)
    for cname in concept_names[:4]:
        dirs = []
        weights = []
        for l in range(24):
            d = all_acts[cname]["positive"][l].mean(0) - all_acts[cname]["negative"][l].mean(0)
            norm = np.linalg.norm(d)
            dirs.append(d / (norm + 1e-10))
            weights.append(norm)
        weights = np.array(weights)
        weights = weights / (weights.sum() + 1e-10)
        # Best single layer direction
        best_layer = int(np.argmax([np.linalg.norm(all_acts[cname]["positive"][l].mean(0) - all_acts[cname]["negative"][l].mean(0)) for l in range(24)]))
        best_dir = dirs[best_layer]
        # Weighted ensemble
        ensemble = sum(w * d for w, d in zip(weights, dirs))
        ensemble = ensemble / (np.linalg.norm(ensemble) + 1e-10)
        cos_sim = float(best_dir @ ensemble)
        print(f"  {cname:20s} | best layer: L{best_layer} | ensemble-best cosine: {cos_sim:.4f} | top 3 weights: {np.sort(weights)[-3:][::-1]}")
    print()


def concept_neuron_mutual_information_pairs(all_acts, concept_names):
    """Phase 1169: Estimate mutual information between top neuron pairs per concept."""
    print("=" * 70)
    print("PHASE 1169: NEURON PAIR MUTUAL INFORMATION")
    print("=" * 70)
    layer = 10
    for cname in concept_names[:3]:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        combined = np.vstack([pos, neg])
        labels = np.array([1]*len(pos) + [0]*len(neg))
        # Find top 5 neurons by MI
        mi = mutual_info_classif(combined, labels, n_neighbors=3, random_state=42)
        top5 = np.argsort(mi)[-5:][::-1]
        # Pairwise correlation among top neurons
        sub = combined[:, top5]
        corr = np.corrcoef(sub.T)
        np.fill_diagonal(corr, 0)
        max_corr = np.abs(corr).max()
        mean_corr = np.abs(corr).mean()
        print(f"  {cname:20s} | top5 MI neurons: {top5.tolist()} | max pairwise |corr|: {max_corr:.4f} | mean: {mean_corr:.4f}")
    print()


def concept_layer_transition_mutual_info(all_acts, concept_names):
    """Phase 1170: MI between concept labels and activations at each layer transition."""
    print("=" * 70)
    print("PHASE 1170: LAYER TRANSITION MUTUAL INFORMATION")
    print("=" * 70)
    for cname in concept_names[:3]:
        mi_vals = []
        for l in range(24):
            pos = all_acts[cname]["positive"][l]
            neg = all_acts[cname]["negative"][l]
            combined = np.vstack([pos, neg])
            labels = np.array([1]*len(pos) + [0]*len(neg))
            # Use projection onto concept direction as single feature
            direction = pos.mean(0) - neg.mean(0)
            proj = combined @ direction
            mi = mutual_info_classif(proj.reshape(-1, 1), labels, n_neighbors=3, random_state=42)[0]
            mi_vals.append(mi)
        peak = int(np.argmax(mi_vals))
        print(f"  {cname:20s} | peak MI layer: L{peak} ({mi_vals[peak]:.4f}) | L0: {mi_vals[0]:.4f} | L23: {mi_vals[23]:.4f}")
    print()


def concept_direction_leave_one_out_cosine_stability(all_acts, concept_names):
    """Phase 1171: Leave-one-out stability of concept directions."""
    print("=" * 70)
    print("PHASE 1171: LEAVE-ONE-OUT COSINE STABILITY")
    print("=" * 70)
    layer = 10
    for cname in concept_names[:4]:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        full_dir = pos.mean(0) - neg.mean(0)
        full_dir = full_dir / (np.linalg.norm(full_dir) + 1e-10)
        cos_sims = []
        for i in range(len(pos)):
            loo_pos = np.delete(pos, i, axis=0)
            loo_dir = loo_pos.mean(0) - neg.mean(0)
            loo_dir = loo_dir / (np.linalg.norm(loo_dir) + 1e-10)
            cos_sims.append(float(full_dir @ loo_dir))
        print(f"  {cname:20s} | mean LOO cosine: {np.mean(cos_sims):.6f} | min: {np.min(cos_sims):.6f} | std: {np.std(cos_sims):.6f}")
    print()


def concept_activation_percentile_profile(all_acts, concept_names):
    """Phase 1172: Percentile profile of concept activations."""
    print("=" * 70)
    print("PHASE 1172: ACTIVATION PERCENTILE PROFILE")
    print("=" * 70)
    layer = 10
    for cname in concept_names[:4]:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        pos_norms = np.linalg.norm(pos, axis=1)
        neg_norms = np.linalg.norm(neg, axis=1)
        p25_pos, p50_pos, p75_pos = np.percentile(pos_norms, [25, 50, 75])
        p25_neg, p50_neg, p75_neg = np.percentile(neg_norms, [25, 50, 75])
        print(f"  {cname:20s} | pos [p25={p25_pos:.1f}, p50={p50_pos:.1f}, p75={p75_pos:.1f}] | neg [p25={p25_neg:.1f}, p50={p50_neg:.1f}, p75={p75_neg:.1f}]")
    print()


def concept_neuron_concept_specificity_entropy_distribution(all_acts, concept_names):
    """Phase 1173: Entropy of concept specificity per neuron."""
    print("=" * 70)
    print("PHASE 1173: NEURON CONCEPT SPECIFICITY ENTROPY DISTRIBUTION")
    print("=" * 70)
    layer = 10
    n_neurons = all_acts[concept_names[0]]["positive"][layer].shape[1]
    entropies = np.zeros(n_neurons)
    for j in range(n_neurons):
        responses = []
        for cname in concept_names:
            pos_mean = all_acts[cname]["positive"][layer][:, j].mean()
            neg_mean = all_acts[cname]["negative"][layer][:, j].mean()
            responses.append(abs(pos_mean - neg_mean))
        responses = np.array(responses)
        probs = responses / (responses.sum() + 1e-10)
        ent = -np.sum(probs * np.log(probs + 1e-10))
        entropies[j] = ent
    max_ent = np.log(len(concept_names))
    low_ent = (entropies < 0.5 * max_ent).sum()
    high_ent = (entropies > 0.9 * max_ent).sum()
    print(f"  Max possible entropy: {max_ent:.3f}")
    print(f"  Specific neurons (ent < 50% max): {low_ent}/{n_neurons}")
    print(f"  Generalist neurons (ent > 90% max): {high_ent}/{n_neurons}")
    print(f"  Mean entropy: {entropies.mean():.3f} ({entropies.mean()/max_ent*100:.1f}% of max)")
    print()


def concept_direction_angle_distribution_shape(all_acts, concept_names):
    """Phase 1174: Shape of the pairwise angle distribution."""
    print("=" * 70)
    print("PHASE 1174: PAIRWISE ANGLE DISTRIBUTION SHAPE")
    print("=" * 70)
    layer = 10
    dirs = {}
    for cname in concept_names:
        d = all_acts[cname]["positive"][layer].mean(0) - all_acts[cname]["negative"][layer].mean(0)
        dirs[cname] = d / (np.linalg.norm(d) + 1e-10)
    angles = []
    for i in range(len(concept_names)):
        for j in range(i+1, len(concept_names)):
            cos = abs(float(dirs[concept_names[i]] @ dirs[concept_names[j]]))
            angles.append(np.degrees(np.arccos(np.clip(cos, 0, 1))))
    angles = np.array(angles)
    from scipy.stats import kurtosis as sp_kurtosis, skew as sp_skew
    print(f"  N pairs: {len(angles)}")
    print(f"  Mean angle: {angles.mean():.1f}° | Std: {angles.std():.1f}°")
    print(f"  Min: {angles.min():.1f}° | Max: {angles.max():.1f}°")
    print(f"  Skewness: {sp_skew(angles):.3f} | Kurtosis: {sp_kurtosis(angles, fisher=True):.3f}")
    print()


def concept_activation_norm_ratio_pos_neg(all_acts, concept_names):
    """Phase 1175: Ratio of activation norms between positive and negative samples."""
    print("=" * 70)
    print("PHASE 1175: ACTIVATION NORM RATIO (POS/NEG)")
    print("=" * 70)
    for cname in concept_names:
        ratios = []
        for l in range(24):
            pos_norm = np.mean(np.linalg.norm(all_acts[cname]["positive"][l], axis=1))
            neg_norm = np.mean(np.linalg.norm(all_acts[cname]["negative"][l], axis=1))
            ratios.append(pos_norm / (neg_norm + 1e-10))
        max_ratio_l = int(np.argmax(np.abs(np.array(ratios) - 1)))
        print(f"  {cname:20s} | max deviation from 1: L{max_ratio_l} (ratio={ratios[max_ratio_l]:.4f}) | mean ratio: {np.mean(ratios):.4f}")
    print()


def concept_neuron_activation_cv_profile(all_acts, concept_names):
    """Phase 1176: Coefficient of variation of neuron activations per concept."""
    print("=" * 70)
    print("PHASE 1176: NEURON CV PROFILE")
    print("=" * 70)
    layer = 10
    for cname in concept_names[:4]:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        combined = np.vstack([pos, neg])
        means = np.abs(combined.mean(0)) + 1e-10
        stds = combined.std(0)
        cvs = stds / means
        print(f"  {cname:20s} | mean CV: {cvs.mean():.3f} | min CV: {cvs.min():.3f} | max CV: {cvs.max():.3f} | low CV neurons (<0.5): {(cvs < 0.5).sum()}")
    print()


def concept_direction_geodesic_vs_euclidean(all_acts, concept_names):
    """Phase 1177: Compare geodesic and Euclidean distances between concept centroids."""
    print("=" * 70)
    print("PHASE 1177: GEODESIC vs EUCLIDEAN DISTANCE")
    print("=" * 70)
    layer = 10
    centroids = {}
    for cname in concept_names:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        centroids[cname] = {
            "pos": pos.mean(0),
            "neg": neg.mean(0)
        }
    for cname in concept_names[:4]:
        pos_c = centroids[cname]["pos"]
        neg_c = centroids[cname]["neg"]
        euclid = np.linalg.norm(pos_c - neg_c)
        # Geodesic on sphere (using normalized vectors)
        pos_n = pos_c / (np.linalg.norm(pos_c) + 1e-10)
        neg_n = neg_c / (np.linalg.norm(neg_c) + 1e-10)
        cos_angle = np.clip(float(pos_n @ neg_n), -1, 1)
        geodesic = np.arccos(cos_angle)
        print(f"  {cname:20s} | Euclidean: {euclid:.3f} | Geodesic: {geodesic:.4f} rad ({np.degrees(geodesic):.1f}°)")
    print()


def concept_activation_layer_signal_autocorrelation(all_acts, concept_names):
    """Phase 1178: Correlation of concept signal across layers."""
    print("=" * 70)
    print("PHASE 1178: CROSS-LAYER SIGNAL AUTOCORRELATION")
    print("=" * 70)
    for cname in concept_names[:3]:
        signals = []
        for l in range(24):
            pos = all_acts[cname]["positive"][l]
            neg = all_acts[cname]["negative"][l]
            d = pos.mean(0) - neg.mean(0)
            signals.append(np.linalg.norm(d))
        signals = np.array(signals)
        # Autocorrelation at various lags
        s_centered = signals - signals.mean()
        var = np.var(signals)
        if var > 1e-10:
            ac = [np.mean(s_centered[:-lag] * s_centered[lag:]) / var if lag > 0 else 1.0 for lag in range(5)]
        else:
            ac = [1.0, 0, 0, 0, 0]
        print(f"  {cname:20s} | autocorr lags 0-4: {' '.join(f'{a:.3f}' for a in ac)}")
    print()


def concept_direction_whitened_cosine_analysis(all_acts, concept_names):
    """Phase 1179: Cosine analysis after whitening transformation."""
    print("=" * 70)
    print("PHASE 1179: WHITENED COSINE ANALYSIS")
    print("=" * 70)
    layer = 10
    # Collect all activations to compute whitening
    all_data = []
    for cname in concept_names:
        all_data.append(all_acts[cname]["positive"][layer])
        all_data.append(all_acts[cname]["negative"][layer])
    all_data = np.vstack(all_data)
    mean = all_data.mean(0)
    cov = np.cov((all_data - mean).T)
    eigvals, eigvecs = np.linalg.eigh(cov)
    eigvals = np.maximum(eigvals, 1e-10)
    W = eigvecs @ np.diag(1.0 / np.sqrt(eigvals)) @ eigvecs.T
    # Compute whitened directions
    dirs_w = {}
    for cname in concept_names:
        pos_w = (all_acts[cname]["positive"][layer] - mean) @ W
        neg_w = (all_acts[cname]["negative"][layer] - mean) @ W
        d = pos_w.mean(0) - neg_w.mean(0)
        dirs_w[cname] = d / (np.linalg.norm(d) + 1e-10)
    max_cos = 0.0
    max_pair = ("", "")
    for i in range(len(concept_names)):
        for j in range(i+1, len(concept_names)):
            cos = abs(float(dirs_w[concept_names[i]] @ dirs_w[concept_names[j]]))
            if cos > max_cos:
                max_cos = cos
                max_pair = (concept_names[i], concept_names[j])
    print(f"  Max whitened cosine: {max_cos:.6f} ({max_pair[0]} vs {max_pair[1]})")
    print(f"  (Lower is better — 0 means perfectly orthogonal after whitening)")
    print()


def concept_activation_cluster_silhouette_score(all_acts, concept_names):
    """Phase 1180: Silhouette score for concept clustering."""
    print("=" * 70)
    print("PHASE 1180: CONCEPT CLUSTER SILHOUETTE SCORE")
    print("=" * 70)
    layer = 10
    for cname in concept_names[:4]:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        combined = np.vstack([pos, neg])
        labels = np.array([1]*len(pos) + [0]*len(neg))
        # Simplified silhouette: for each point, compare mean intra-cluster dist to mean inter-cluster dist
        sil_scores = []
        for i in range(len(combined)):
            same = combined[labels == labels[i]]
            diff = combined[labels != labels[i]]
            a = np.mean(np.linalg.norm(same - combined[i], axis=1))
            b = np.mean(np.linalg.norm(diff - combined[i], axis=1))
            sil_scores.append((b - a) / (max(a, b) + 1e-10))
        mean_sil = np.mean(sil_scores)
        print(f"  {cname:20s} | silhouette: {mean_sil:.4f} (1=perfect, 0=overlapping, -1=misassigned)")
    print()


def concept_direction_rank_deficiency_analysis(all_acts, concept_names):
    """Phase 1181: Analyze rank deficiency of the concept direction matrix."""
    print("=" * 70)
    print("PHASE 1181: DIRECTION MATRIX RANK DEFICIENCY")
    print("=" * 70)
    layer = 10
    dir_matrix = []
    for cname in concept_names:
        d = all_acts[cname]["positive"][layer].mean(0) - all_acts[cname]["negative"][layer].mean(0)
        dir_matrix.append(d)
    dir_matrix = np.array(dir_matrix)
    svals = np.linalg.svd(dir_matrix, compute_uv=False)
    rank_90 = np.searchsorted(np.cumsum(svals ** 2) / (np.sum(svals ** 2) + 1e-10), 0.90) + 1
    rank_99 = np.searchsorted(np.cumsum(svals ** 2) / (np.sum(svals ** 2) + 1e-10), 0.99) + 1
    print(f"  Direction matrix shape: {dir_matrix.shape}")
    print(f"  Singular values: {svals[:8]}")
    print(f"  Rank for 90% energy: {rank_90} | 99% energy: {rank_99}")
    print(f"  Condition number: {svals[0]/(svals[-1]+1e-10):.2f}")
    print()


def concept_neuron_dead_alive_ratio(all_acts, concept_names):
    """Phase 1182: Ratio of dead (near-zero) vs alive neurons per concept."""
    print("=" * 70)
    print("PHASE 1182: DEAD vs ALIVE NEURON RATIO")
    print("=" * 70)
    layer = 10
    for cname in concept_names:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        combined = np.vstack([pos, neg])
        max_abs = np.abs(combined).max(0)
        dead = (max_abs < 0.01).sum()
        alive = combined.shape[1] - dead
        print(f"  {cname:20s} | alive: {alive} | dead: {dead} | ratio: {alive/(dead+1):.1f}")
    print()


def concept_direction_projection_distribution_overlap(all_acts, concept_names):
    """Phase 1183: Overlap between pos/neg projection distributions."""
    print("=" * 70)
    print("PHASE 1183: PROJECTION DISTRIBUTION OVERLAP")
    print("=" * 70)
    layer = 10
    for cname in concept_names:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        direction = pos.mean(0) - neg.mean(0)
        direction = direction / (np.linalg.norm(direction) + 1e-10)
        pos_proj = pos @ direction
        neg_proj = neg @ direction
        # Overlap: fraction of neg projections above min(pos) and pos below max(neg)
        overlap_region = max(0, min(pos_proj.max(), neg_proj.max()) - max(pos_proj.min(), neg_proj.min()))
        total_range = max(pos_proj.max(), neg_proj.max()) - min(pos_proj.min(), neg_proj.min())
        overlap_frac = overlap_region / (total_range + 1e-10)
        print(f"  {cname:20s} | overlap: {overlap_frac:.4f} | pos range: [{pos_proj.min():.2f}, {pos_proj.max():.2f}] | neg range: [{neg_proj.min():.2f}, {neg_proj.max():.2f}]")
    print()


def concept_activation_pca_explained_variance(all_acts, concept_names):
    """Phase 1184: PCA explained variance for concept activations."""
    print("=" * 70)
    print("PHASE 1184: PCA EXPLAINED VARIANCE")
    print("=" * 70)
    layer = 10
    for cname in concept_names[:4]:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        combined = np.vstack([pos, neg])
        centered = combined - combined.mean(0)
        cov = np.cov(centered.T)
        eigvals = np.linalg.eigvalsh(cov)[::-1]
        cumvar = np.cumsum(eigvals) / (eigvals.sum() + 1e-10)
        n_for_90 = np.searchsorted(cumvar, 0.90) + 1
        n_for_95 = np.searchsorted(cumvar, 0.95) + 1
        print(f"  {cname:20s} | dims for 90%: {n_for_90} | 95%: {n_for_95} | PC1: {eigvals[0]/eigvals.sum()*100:.1f}%")
    print()


def concept_neuron_response_symmetry_test(all_acts, concept_names):
    """Phase 1185: Test symmetry of neuron responses (positive vs negative concept)."""
    print("=" * 70)
    print("PHASE 1185: NEURON RESPONSE SYMMETRY TEST")
    print("=" * 70)
    layer = 10
    for cname in concept_names[:4]:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        pos_mean = pos.mean(0)
        neg_mean = neg.mean(0)
        grand_mean = np.vstack([pos, neg]).mean(0)
        pos_dev = pos_mean - grand_mean
        neg_dev = neg_mean - grand_mean
        # Perfect symmetry: pos_dev = -neg_dev
        symmetry = np.corrcoef(pos_dev, -neg_dev)[0, 1]
        asym_norm = np.linalg.norm(pos_dev + neg_dev) / (np.linalg.norm(pos_dev) + 1e-10)
        print(f"  {cname:20s} | symmetry corr: {symmetry:.6f} | asymmetry norm: {asym_norm:.6f}")
    print()


def concept_direction_concept_direction_gram_schmidt_residuals(all_acts, concept_names):
    """Phase 1186: Gram-Schmidt residual norms after orthogonalization."""
    print("=" * 70)
    print("PHASE 1186: GRAM-SCHMIDT RESIDUAL NORMS")
    print("=" * 70)
    layer = 10
    dirs = []
    for cname in concept_names:
        d = all_acts[cname]["positive"][layer].mean(0) - all_acts[cname]["negative"][layer].mean(0)
        dirs.append(d)
    # Gram-Schmidt
    ortho = []
    residual_norms = []
    for i, d in enumerate(dirs):
        v = d.copy()
        for u in ortho:
            v = v - (v @ u) * u
        norm = np.linalg.norm(v)
        residual_norms.append(norm / (np.linalg.norm(d) + 1e-10))
        if norm > 1e-10:
            ortho.append(v / norm)
    for i, (cname, rn) in enumerate(zip(concept_names, residual_norms)):
        print(f"  {cname:20s} (order {i}) | residual fraction: {rn:.6f}")
    print()


def concept_activation_extreme_sample_analysis(all_acts, concept_names):
    """Phase 1187: Analyze extreme (outlier) samples per concept."""
    print("=" * 70)
    print("PHASE 1187: EXTREME SAMPLE ANALYSIS")
    print("=" * 70)
    layer = 10
    for cname in concept_names[:4]:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        direction = pos.mean(0) - neg.mean(0)
        direction = direction / (np.linalg.norm(direction) + 1e-10)
        pos_proj = pos @ direction
        neg_proj = neg @ direction
        pos_extreme = pos_proj.max()
        neg_extreme = neg_proj.min()
        pos_median = np.median(pos_proj)
        neg_median = np.median(neg_proj)
        print(f"  {cname:20s} | pos extreme/median: {pos_extreme/pos_median:.3f} | neg extreme/median: {neg_extreme/(neg_median+1e-10):.3f}")
    print()


def concept_direction_cross_concept_projection_matrix(all_acts, concept_names):
    """Phase 1188: Cross-concept projection matrix (project each onto all others)."""
    print("=" * 70)
    print("PHASE 1188: CROSS-CONCEPT PROJECTION MATRIX")
