def concept_direction_angular_velocity_profile(all_acts, concept_names):
    """Phase 1201: Angular velocity of concept directions across layers."""
    print("=" * 70)
    print("PHASE 1201: DIRECTION ANGULAR VELOCITY PROFILE")
    print("=" * 70)
    for cname in concept_names[:4]:
        angular_vels = []
        for l in range(23):
            d1 = all_acts[cname]["positive"][l].mean(0) - all_acts[cname]["negative"][l].mean(0)
            d2 = all_acts[cname]["positive"][l+1].mean(0) - all_acts[cname]["negative"][l+1].mean(0)
            d1 = d1 / (np.linalg.norm(d1) + 1e-10)
            d2 = d2 / (np.linalg.norm(d2) + 1e-10)
            angle = np.degrees(np.arccos(np.clip(float(d1 @ d2), -1, 1)))
            angular_vels.append(angle)
        max_vel_l = int(np.argmax(angular_vels))
        print(f"  {cname:20s} | max angular vel: {angular_vels[max_vel_l]:.1f}°/layer at L{max_vel_l} | mean: {np.mean(angular_vels):.1f}°/layer")
    print()


def concept_neuron_activation_distribution_moments(all_acts, concept_names):
    """Phase 1202: Higher-order moments of neuron activation distributions."""
    print("=" * 70)
    print("PHASE 1202: ACTIVATION DISTRIBUTION MOMENTS")
    print("=" * 70)
    from scipy.stats import kurtosis, skew
    layer = 10
    for cname in concept_names[:4]:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        combined = np.vstack([pos, neg])
        mean_kurt = np.mean(kurtosis(combined, axis=0, fisher=True))
        mean_skew = np.mean(np.abs(skew(combined, axis=0)))
        print(f"  {cname:20s} | mean kurtosis: {mean_kurt:.3f} | mean |skew|: {mean_skew:.3f}")
    print()


def concept_direction_pairwise_angle_layer_evolution(all_acts, concept_names):
    """Phase 1203: Track pairwise angles between specific concept pairs across layers."""
    print("=" * 70)
    print("PHASE 1203: PAIRWISE ANGLE EVOLUTION ACROSS LAYERS")
    print("=" * 70)
    pairs = [("sentiment", "emotion_joy_anger"), ("formality", "complexity"), ("certainty", "subjectivity")]
    for c1, c2 in pairs:
        if c1 in concept_names and c2 in concept_names:
            angles = []
            for l in range(24):
                d1 = all_acts[c1]["positive"][l].mean(0) - all_acts[c1]["negative"][l].mean(0)
                d2 = all_acts[c2]["positive"][l].mean(0) - all_acts[c2]["negative"][l].mean(0)
                cos = float(d1 @ d2 / (np.linalg.norm(d1) * np.linalg.norm(d2) + 1e-10))
                angles.append(np.degrees(np.arccos(np.clip(abs(cos), 0, 1))))
            print(f"  {c1:12s} vs {c2:12s} | L0: {angles[0]:.1f}° | L12: {angles[12]:.1f}° | L23: {angles[23]:.1f}° | range: [{min(angles):.1f}°, {max(angles):.1f}°]")
    print()


def concept_activation_effective_dimensionality_per_layer(all_acts, concept_names):
    """Phase 1204: Effective dimensionality at each layer."""
    print("=" * 70)
    print("PHASE 1204: EFFECTIVE DIMENSIONALITY PER LAYER")
    print("=" * 70)
    for cname in concept_names[:3]:
        eff_dims = []
        for l in range(24):
            combined = np.vstack([all_acts[cname]["positive"][l], all_acts[cname]["negative"][l]])
            cov = np.cov(combined.T)
            eigvals = np.maximum(np.linalg.eigvalsh(cov), 0)
            total = eigvals.sum() + 1e-10
            eff_dim = total ** 2 / (np.sum(eigvals ** 2) + 1e-10)
            eff_dims.append(eff_dim)
        print(f"  {cname:20s} | min eff_dim: L{int(np.argmin(eff_dims))} ({min(eff_dims):.1f}) | max: L{int(np.argmax(eff_dims))} ({max(eff_dims):.1f})")
    print()


def concept_neuron_top_bottom_magnitude_asymmetry(all_acts, concept_names):
    """Phase 1205: Compare top activating vs bottom activating neurons."""
    print("=" * 70)
    print("PHASE 1205: TOP vs BOTTOM NEURON MAGNITUDE ASYMMETRY")
    print("=" * 70)
    layer = 10
    for cname in concept_names[:4]:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        diff = pos.mean(0) - neg.mean(0)
        top10 = np.argsort(diff)[-10:]
        bot10 = np.argsort(diff)[:10]
        top_magnitude = np.mean(np.abs(diff[top10]))
        bot_magnitude = np.mean(np.abs(diff[bot10]))
        print(f"  {cname:20s} | top10 mag: {top_magnitude:.4f} | bot10 mag: {bot_magnitude:.4f} | ratio: {top_magnitude/(bot_magnitude+1e-10):.3f}")
    print()


def concept_direction_information_gain_per_layer(all_acts, concept_names):
    """Phase 1206: Information gain at each layer for concept discrimination."""
    print("=" * 70)
    print("PHASE 1206: INFORMATION GAIN PER LAYER")
    print("=" * 70)
    for cname in concept_names[:4]:
        gains = []
        for l in range(24):
            pos = all_acts[cname]["positive"][l]
            neg = all_acts[cname]["negative"][l]
            d = pos.mean(0) - neg.mean(0)
            # Fisher discriminant ratio as proxy for info gain
            pooled_var = 0.5 * (np.var(pos, axis=0) + np.var(neg, axis=0))
            fdr = np.sum(d ** 2 / (pooled_var + 1e-10))
            gains.append(fdr)
        best_l = int(np.argmax(gains))
        print(f"  {cname:20s} | best layer: L{best_l} (FDR={gains[best_l]:.0f}) | worst: L{int(np.argmin(gains))} (FDR={min(gains):.0f})")
    print()


def concept_activation_inter_concept_distance_matrix(all_acts, concept_names):
    """Phase 1207: Distance matrix between concept centroids."""
    print("=" * 70)
    print("PHASE 1207: INTER-CONCEPT CENTROID DISTANCE")
    print("=" * 70)
    layer = 10
    centroids = {}
    for cname in concept_names:
        centroids[cname] = np.vstack([all_acts[cname]["positive"][layer], all_acts[cname]["negative"][layer]]).mean(0)
    dists = []
    for i in range(len(concept_names)):
        for j in range(i+1, len(concept_names)):
            d = np.linalg.norm(centroids[concept_names[i]] - centroids[concept_names[j]])
            dists.append((concept_names[i], concept_names[j], d))
    dists.sort(key=lambda x: x[2])
    print("  Closest pairs:")
    for c1, c2, d in dists[:3]:
        print(f"    {c1:12s} - {c2:12s}: {d:.3f}")
    print("  Farthest pairs:")
    for c1, c2, d in dists[-3:]:
        print(f"    {c1:12s} - {c2:12s}: {d:.3f}")
    print()


def concept_neuron_concept_neuron_activation_correlation_with_labels(all_acts, concept_names):
    """Phase 1208: Point-biserial correlation between neuron activations and labels."""
    print("=" * 70)
    print("PHASE 1208: NEURON-LABEL POINT-BISERIAL CORRELATION")
    print("=" * 70)
    layer = 10
    for cname in concept_names[:4]:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        combined = np.vstack([pos, neg])
        labels = np.array([1]*len(pos) + [0]*len(neg))
        corrs = np.array([np.corrcoef(combined[:, j], labels)[0, 1] for j in range(combined.shape[1])])
        top5 = np.argsort(np.abs(corrs))[-5:][::-1]
        print(f"  {cname:20s} | max |corr|: {np.abs(corrs).max():.4f} | top neurons: {top5.tolist()} | mean |corr|: {np.abs(corrs).mean():.4f}")
    print()


def concept_direction_concept_direction_projection_overlap_area(all_acts, concept_names):
    """Phase 1209: Area of overlap between projection distributions of different concepts."""
    print("=" * 70)
    print("PHASE 1209: CROSS-CONCEPT PROJECTION OVERLAP")
    print("=" * 70)
    layer = 10
    # For each pair, project both concept's data onto each other's directions
    pairs = [("sentiment", "emotion_joy_anger"), ("formality", "certainty"), ("temporal", "complexity")]
    for c1, c2 in pairs:
        if c1 in concept_names and c2 in concept_names:
            d1 = all_acts[c1]["positive"][layer].mean(0) - all_acts[c1]["negative"][layer].mean(0)
            d1 = d1 / (np.linalg.norm(d1) + 1e-10)
            # Project c2 data onto c1 direction
            c2_pos_proj = all_acts[c2]["positive"][layer] @ d1
            c2_neg_proj = all_acts[c2]["negative"][layer] @ d1
            sep = abs(c2_pos_proj.mean() - c2_neg_proj.mean())
            spread = np.std(np.concatenate([c2_pos_proj, c2_neg_proj]))
            print(f"  {c2:12s} on {c1:12s} dir | sep: {sep:.4f} | spread: {spread:.4f} | ratio: {sep/(spread+1e-10):.4f}")
    print()


def concept_activation_global_statistics_1210(all_acts, concept_names):
    """Phase 1210: Global activation statistics across all concepts and layers."""
    print("=" * 70)
    print("PHASE 1210: GLOBAL ACTIVATION STATISTICS")
    print("=" * 70)
    total_samples = 0
    total_norm = 0
    total_var = 0
    for cname in concept_names:
        for l in range(24):
            pos = all_acts[cname]["positive"][l]
            neg = all_acts[cname]["negative"][l]
            combined = np.vstack([pos, neg])
            total_samples += len(combined)
            total_norm += np.sum(np.linalg.norm(combined, axis=1))
            total_var += np.var(combined)
    mean_norm = total_norm / total_samples
    mean_var = total_var / (len(concept_names) * 24)
    print(f"  Total samples across all concepts/layers: {total_samples}")
    print(f"  Mean activation norm: {mean_norm:.3f}")
    print(f"  Mean per-cell variance: {mean_var:.6f}")
    print(f"  Concepts: {len(concept_names)} | Layers: 24 | Hidden dim: {all_acts[concept_names[0]]['positive'][0].shape[1]}")
    print()


def concept_direction_bootstrap_confidence_interval(all_acts, concept_names):
    """Phase 1211: Bootstrap confidence intervals for concept direction angles."""
    print("=" * 70)
    print("PHASE 1211: BOOTSTRAP CONFIDENCE INTERVALS FOR ANGLES")
    print("=" * 70)
    layer = 10
    rng = np.random.default_rng(42)
    for cname in concept_names[:4]:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        norms = []
        for _ in range(200):
            bp = pos[rng.integers(len(pos), size=len(pos))]
            bn = neg[rng.integers(len(neg), size=len(neg))]
            d = bp.mean(0) - bn.mean(0)
            norms.append(np.linalg.norm(d))
        ci_low, ci_high = np.percentile(norms, [2.5, 97.5])
        print(f"  {cname:20s} | norm 95% CI: [{ci_low:.3f}, {ci_high:.3f}] | width: {ci_high-ci_low:.3f}")
    print()


def concept_neuron_activation_tail_heaviness(all_acts, concept_names):
    """Phase 1212: Measure tail heaviness of neuron activation distributions."""
    print("=" * 70)
    print("PHASE 1212: NEURON ACTIVATION TAIL HEAVINESS")
    print("=" * 70)
    layer = 10
    for cname in concept_names[:4]:
        combined = np.vstack([all_acts[cname]["positive"][layer], all_acts[cname]["negative"][layer]])
        # Tail ratio: fraction of values beyond 2 std
        stds = combined.std(0)
        means = combined.mean(0)
        tail_fracs = []
        for j in range(combined.shape[1]):
            if stds[j] > 1e-10:
                beyond = np.abs(combined[:, j] - means[j]) > 2 * stds[j]
                tail_fracs.append(beyond.mean())
        mean_tail = np.mean(tail_fracs)
        expected_gaussian = 0.0455  # for 2-sigma
        print(f"  {cname:20s} | mean tail frac: {mean_tail:.4f} (Gaussian: {expected_gaussian:.4f}) | {'heavier' if mean_tail > expected_gaussian else 'lighter'} tails")
    print()


def concept_direction_projection_separability_index(all_acts, concept_names):
    """Phase 1213: Separability index based on projection histograms."""
    print("=" * 70)
    print("PHASE 1213: PROJECTION SEPARABILITY INDEX")
    print("=" * 70)
    layer = 10
    for cname in concept_names:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        d = pos.mean(0) - neg.mean(0)
        d = d / (np.linalg.norm(d) + 1e-10)
        pos_proj = pos @ d
        neg_proj = neg @ d
        # Bhattacharyya distance
        m1, s1 = pos_proj.mean(), pos_proj.std() + 1e-10
        m2, s2 = neg_proj.mean(), neg_proj.std() + 1e-10
        bhatt = 0.25 * np.log(0.25 * (s1**2/s2**2 + s2**2/s1**2 + 2)) + 0.25 * ((m1-m2)**2 / (s1**2 + s2**2))
        print(f"  {cname:20s} | Bhattacharyya dist: {bhatt:.4f} (higher=more separable)")
    print()


def concept_activation_layer_wise_variance_decomposition(all_acts, concept_names):
    """Phase 1214: Decompose variance into between-concept and within-concept at each layer."""
    print("=" * 70)
    print("PHASE 1214: LAYER-WISE VARIANCE DECOMPOSITION")
    print("=" * 70)
    for l in [0, 6, 12, 18, 23]:
        all_data = []
        all_labels = []
        for ci, cname in enumerate(concept_names):
            data = np.vstack([all_acts[cname]["positive"][l], all_acts[cname]["negative"][l]])
            all_data.append(data)
            all_labels.extend([ci] * len(data))
        all_data = np.vstack(all_data)
        all_labels = np.array(all_labels)
        grand_mean = all_data.mean(0)
        total_var = np.var(all_data, axis=0).sum()
        between_var = sum(
            np.sum((all_data[all_labels == ci].mean(0) - grand_mean) ** 2) * (all_labels == ci).sum()
            for ci in range(len(concept_names))
        ) / len(all_data)
        print(f"  L{l:2d} | between/total: {between_var/total_var*100:.2f}%")
    print()


def concept_neuron_response_within_class_consistency(all_acts, concept_names):
    """Phase 1215: How consistent are neuron responses across samples of the same concept."""
    print("=" * 70)
    print("PHASE 1215: NEURON WITHIN-CLASS CONSISTENCY")
    print("=" * 70)
    layer = 10
    for cname in concept_names[:4]:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        # ICC-like measure: within-class variance vs total
        pos_within = np.mean(np.var(pos, axis=0))
        neg_within = np.mean(np.var(neg, axis=0))
        combined = np.vstack([pos, neg])
        total = np.mean(np.var(combined, axis=0))
        consistency = 1 - (0.5*(pos_within + neg_within)) / (total + 1e-10)
        print(f"  {cname:20s} | consistency: {consistency:.4f} (1=perfectly consistent by class)")
    print()


def concept_direction_mutual_angle_stability_bootstrap(all_acts, concept_names):
    """Phase 1216: Bootstrap stability of pairwise concept angles."""
    print("=" * 70)
    print("PHASE 1216: PAIRWISE ANGLE BOOTSTRAP STABILITY")
    print("=" * 70)
    layer = 10
    rng = np.random.default_rng(42)
    pairs = [("sentiment", "emotion_joy_anger"), ("formality", "complexity"), ("certainty", "temporal")]
    for c1, c2 in pairs:
        if c1 in concept_names and c2 in concept_names:
            angles = []
            for _ in range(200):
                p1 = all_acts[c1]["positive"][layer]
                n1 = all_acts[c1]["negative"][layer]
                p2 = all_acts[c2]["positive"][layer]
                n2 = all_acts[c2]["negative"][layer]
                bp1 = p1[rng.integers(len(p1), size=len(p1))]
                bn1 = n1[rng.integers(len(n1), size=len(n1))]
                bp2 = p2[rng.integers(len(p2), size=len(p2))]
                bn2 = n2[rng.integers(len(n2), size=len(n2))]
                d1 = bp1.mean(0) - bn1.mean(0)
                d2 = bp2.mean(0) - bn2.mean(0)
                cos = abs(float(d1 @ d2 / (np.linalg.norm(d1) * np.linalg.norm(d2) + 1e-10)))
                angles.append(np.degrees(np.arccos(np.clip(cos, 0, 1))))
            print(f"  {c1:12s} vs {c2:12s} | mean: {np.mean(angles):.1f}° | CI: [{np.percentile(angles, 2.5):.1f}°, {np.percentile(angles, 97.5):.1f}°]")
    print()


def concept_activation_neuron_importance_gini(all_acts, concept_names):
    """Phase 1217: Gini coefficient of neuron importance distribution."""
    print("=" * 70)
    print("PHASE 1217: NEURON IMPORTANCE GINI COEFFICIENT")
    print("=" * 70)
    layer = 10
    for cname in concept_names:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        importance = np.abs(pos.mean(0) - neg.mean(0))
        sorted_imp = np.sort(importance)
        n = len(sorted_imp)
        cumsum = np.cumsum(sorted_imp)
        gini = 1 - 2 * cumsum.sum() / (n * cumsum[-1] + 1e-10) + 1/n
        print(f"  {cname:20s} | Gini: {gini:.4f} (1=maximally unequal, 0=uniform)")
    print()


def concept_direction_concept_direction_angle_to_identity(all_acts, concept_names):
    """Phase 1218: Angle between concept direction and principal axes."""
    print("=" * 70)
    print("PHASE 1218: DIRECTION ANGLE TO PRINCIPAL AXES")
    print("=" * 70)
    layer = 10
    for cname in concept_names[:4]:
        d = all_acts[cname]["positive"][layer].mean(0) - all_acts[cname]["negative"][layer].mean(0)
        d = d / (np.linalg.norm(d) + 1e-10)
        # Angle to nearest principal axis (unit vector along one dimension)
        max_component = np.abs(d).max()
        max_idx = int(np.argmax(np.abs(d)))
        angle = np.degrees(np.arccos(np.clip(max_component, 0, 1)))
        print(f"  {cname:20s} | closest axis: neuron {max_idx} | angle: {angle:.1f}° | max component: {max_component:.4f}")
    print()


def concept_neuron_concept_neuron_response_range_per_layer(all_acts, concept_names):
    """Phase 1219: Range of neuron responses across layers."""
    print("=" * 70)
    print("PHASE 1219: NEURON RESPONSE RANGE PER LAYER")
    print("=" * 70)
    for cname in concept_names[:3]:
        ranges = []
        for l in range(24):
            combined = np.vstack([all_acts[cname]["positive"][l], all_acts[cname]["negative"][l]])
            r = combined.max() - combined.min()
            ranges.append(r)
        print(f"  {cname:20s} | min range: L{int(np.argmin(ranges))} ({min(ranges):.2f}) | max range: L{int(np.argmax(ranges))} ({max(ranges):.2f})")
    print()


def concept_direction_orthogonality_quality_index(all_acts, concept_names):
    """Phase 1220: Composite quality index for direction orthogonality."""
    print("=" * 70)
    print("PHASE 1220: ORTHOGONALITY QUALITY INDEX")
    print("=" * 70)
    layer = 10
    dirs = []
    for cname in concept_names:
        d = all_acts[cname]["positive"][layer].mean(0) - all_acts[cname]["negative"][layer].mean(0)
        dirs.append(d / (np.linalg.norm(d) + 1e-10))
    dirs = np.array(dirs)
    gram = dirs @ dirs.T
    np.fill_diagonal(gram, 0)
    max_cos = np.abs(gram).max()
    mean_cos = np.abs(gram).mean()
    det = np.linalg.det(gram + np.eye(len(dirs)))
    cond = np.linalg.cond(gram + np.eye(len(dirs)))
    quality = (1 - max_cos) * (1 - mean_cos) * min(1, det)
    print(f"  Max |cosine|: {max_cos:.6f}")
    print(f"  Mean |cosine|: {mean_cos:.6f}")
    print(f"  Gram det: {det:.6f} | cond: {cond:.2f}")
    print(f"  Quality index: {quality:.6f}")
    print()


def concept_direction_random_projection_sep_preservation(all_acts, concept_names):
    """Phase 1221: Test if random projections preserve concept separability."""
    print("=" * 70)
    print("PHASE 1221: RANDOM PROJECTION SEPARABILITY PRESERVATION")
    print("=" * 70)
    layer = 10
    rng = np.random.default_rng(42)
    d = all_acts[concept_names[0]]["positive"][layer].shape[1]
    for proj_dim in [50, 100, 200]:
        R = rng.standard_normal((d, proj_dim)) / np.sqrt(proj_dim)
        preserved = []
        for cname in concept_names[:4]:
            pos = all_acts[cname]["positive"][layer] @ R
            neg = all_acts[cname]["negative"][layer] @ R
            orig_sep = np.linalg.norm(all_acts[cname]["positive"][layer].mean(0) - all_acts[cname]["negative"][layer].mean(0))
            proj_sep = np.linalg.norm(pos.mean(0) - neg.mean(0))
            preserved.append(proj_sep / (orig_sep + 1e-10))
        print(f"  dim={proj_dim:3d} | mean sep preservation: {np.mean(preserved):.4f} | min: {np.min(preserved):.4f}")
    print()


def concept_neuron_activation_mode_count_histogram(all_acts, concept_names):
    """Phase 1222: Estimate number of modes in neuron activation distributions."""
    print("=" * 70)
    print("PHASE 1222: NEURON ACTIVATION MODE COUNT HISTOGRAM")
    print("=" * 70)
    layer = 10
    for cname in concept_names[:3]:
        combined = np.vstack([all_acts[cname]["positive"][layer], all_acts[cname]["negative"][layer]])
        multimodal_count = 0
        for j in range(0, combined.shape[1], 10):  # sample every 10th neuron
            vals = combined[:, j]
            hist, edges = np.histogram(vals, bins=20)
            peaks = 0
            for k in range(1, len(hist)-1):
                if hist[k] > hist[k-1] and hist[k] > hist[k+1]:
                    peaks += 1
            if peaks >= 2:
                multimodal_count += 1
        total_checked = combined.shape[1] // 10
        print(f"  {cname:20s} | multimodal neurons: {multimodal_count}/{total_checked} ({100*multimodal_count/(total_checked+1):.1f}%)")
    print()


def concept_direction_gram_schmidt_orthogonalization_effect(all_acts, concept_names):
    """Phase 1223: Measure incremental orthogonalization effect."""
    print("=" * 70)
    print("PHASE 1223: GRAM-SCHMIDT ORTHOGONALIZATION EFFECT")
    print("=" * 70)
    layer = 10
    dirs = []
    for cname in concept_names:
        d = all_acts[cname]["positive"][layer].mean(0) - all_acts[cname]["negative"][layer].mean(0)
        dirs.append(d / (np.linalg.norm(d) + 1e-10))
    # Before orthogonalization
    cos_before = []
    for i in range(len(dirs)):
        for j in range(i+1, len(dirs)):
            cos_before.append(abs(float(dirs[i] @ dirs[j])))
    # After Gram-Schmidt
    ortho = []
    for d in dirs:
        v = d.copy()
        for u in ortho:
            v = v - (v @ u) * u
        n = np.linalg.norm(v)
        if n > 1e-10:
            ortho.append(v / n)
    cos_after = []
    for i in range(len(ortho)):
        for j in range(i+1, len(ortho)):
            cos_after.append(abs(float(ortho[i] @ ortho[j])))
    print(f"  Before GS: mean |cos|={np.mean(cos_before):.6f} max={np.max(cos_before):.6f}")
    print(f"  After GS:  mean |cos|={np.mean(cos_after):.6f} max={np.max(cos_after):.6f}")
    print()


def concept_activation_layer_transition_curvature(all_acts, concept_names):
    """Phase 1224: Smoothness of activation transitions between layers."""
    print("=" * 70)
    print("PHASE 1224: LAYER TRANSITION CURVATURE")
    print("=" * 70)
    for cname in concept_names[:4]:
        smoothness = []
        for l in range(22):
            m1 = np.vstack([all_acts[cname]["positive"][l], all_acts[cname]["negative"][l]]).mean(0)
            m2 = np.vstack([all_acts[cname]["positive"][l+1], all_acts[cname]["negative"][l+1]]).mean(0)
            m3 = np.vstack([all_acts[cname]["positive"][l+2], all_acts[cname]["negative"][l+2]]).mean(0)
            # Second difference (curvature)
            curvature = np.linalg.norm(m3 - 2*m2 + m1)
            smoothness.append(curvature)
        roughest = int(np.argmax(smoothness))
        print(f"  {cname:20s} | roughest: L{roughest}-L{roughest+2} ({smoothness[roughest]:.3f}) | mean curvature: {np.mean(smoothness):.3f}")
    print()


def concept_neuron_concept_neuron_max_discriminative_layer(all_acts, concept_names):
    """Phase 1225: Find the most discriminative layer for each top neuron."""
    print("=" * 70)
    print("PHASE 1225: MAX DISCRIMINATIVE LAYER PER TOP NEURON")
    print("=" * 70)
    for cname in concept_names[:3]:
        # Find top 3 neurons at the best layer first
        best_layer = 10
        diff = all_acts[cname]["positive"][best_layer].mean(0) - all_acts[cname]["negative"][best_layer].mean(0)
        top3 = np.argsort(np.abs(diff))[-3:][::-1]
        for n in top3:
            best_l = 0
            best_d = 0
            for l in range(24):
                d = abs(all_acts[cname]["positive"][l][:, n].mean() - all_acts[cname]["negative"][l][:, n].mean())
                if d > best_d:
                    best_d = d
                    best_l = l
            print(f"  {cname:20s} | neuron {n:4d} | best layer: L{best_l} (disc={best_d:.4f})")
    print()


def concept_direction_concept_direction_mean_field_analysis(all_acts, concept_names):
    """Phase 1226: Mean-field approximation of concept interactions."""
    print("=" * 70)
    print("PHASE 1226: MEAN-FIELD CONCEPT INTERACTION ANALYSIS")
    print("=" * 70)
    layer = 10
    dirs = {}
    for cname in concept_names:
        d = all_acts[cname]["positive"][layer].mean(0) - all_acts[cname]["negative"][layer].mean(0)
        dirs[cname] = d / (np.linalg.norm(d) + 1e-10)
    # Mean field: for each concept, compute mean interaction with all others
    for cname in concept_names:
        interactions = [abs(float(dirs[cname] @ dirs[c2])) for c2 in concept_names if c2 != cname]
        mean_int = np.mean(interactions)
        max_int = np.max(interactions)
        max_partner = [c2 for c2 in concept_names if c2 != cname][int(np.argmax(interactions))]
        print(f"  {cname:20s} | mean interaction: {mean_int:.4f} | max: {max_int:.4f} ({max_partner})")
    print()


def concept_activation_principal_angle_between_subspaces(all_acts, concept_names):
    """Phase 1227: Principal angles between positive and negative subspaces."""
    print("=" * 70)
    print("PHASE 1227: PRINCIPAL ANGLES POS vs NEG SUBSPACES")
    print("=" * 70)
    layer = 10
    k = 3  # subspace dim
    for cname in concept_names[:4]:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        # PCA on each
        pos_c = pos - pos.mean(0)
        neg_c = neg - neg.mean(0)
        _, _, Vp = np.linalg.svd(pos_c, full_matrices=False)
        _, _, Vn = np.linalg.svd(neg_c, full_matrices=False)
        M = Vp[:k] @ Vn[:k].T
        cos_angles = np.linalg.svd(M, compute_uv=False)
        angles = np.degrees(np.arccos(np.clip(cos_angles, 0, 1)))
        print(f"  {cname:20s} | principal angles: {', '.join(f'{a:.1f}°' for a in angles)}")
    print()


def concept_neuron_concept_neuron_activation_quantile_difference(all_acts, concept_names):
    """Phase 1228: Quantile differences between pos/neg activations."""
    print("=" * 70)
    print("PHASE 1228: ACTIVATION QUANTILE DIFFERENCES")
    print("=" * 70)
    layer = 10
    for cname in concept_names[:4]:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        direction = pos.mean(0) - neg.mean(0)
        direction = direction / (np.linalg.norm(direction) + 1e-10)
        pos_proj = pos @ direction
        neg_proj = neg @ direction
        for q in [10, 25, 50, 75, 90]:
            pq = np.percentile(pos_proj, q)
            nq = np.percentile(neg_proj, q)
            if cname == concept_names[0]:
                print(f"  {cname:20s} | Q{q:2d}: pos={pq:.3f} neg={nq:.3f} gap={pq-nq:.3f}")
        if cname != concept_names[0]:
            print(f"  {cname:20s} | Q50 gap={np.median(pos_proj)-np.median(neg_proj):.3f} | Q10 gap={np.percentile(pos_proj,10)-np.percentile(neg_proj,10):.3f}")
    print()


def concept_direction_concept_direction_concept_pair_entanglement_score(all_acts, concept_names):
    """Phase 1229: Entanglement score between concept pairs."""
    print("=" * 70)
    print("PHASE 1229: CONCEPT PAIR ENTANGLEMENT SCORE")
    print("=" * 70)
    layer = 10
    pairs = [(concept_names[i], concept_names[j]) for i in range(len(concept_names)) for j in range(i+1, len(concept_names))]
    entanglements = []
    for c1, c2 in pairs:
        d1 = all_acts[c1]["positive"][layer].mean(0) - all_acts[c1]["negative"][layer].mean(0)
        d2 = all_acts[c2]["positive"][layer].mean(0) - all_acts[c2]["negative"][layer].mean(0)
        d1 = d1 / (np.linalg.norm(d1) + 1e-10)
        d2 = d2 / (np.linalg.norm(d2) + 1e-10)
        cos = abs(float(d1 @ d2))
        # Also check if c1's direction predicts c2
        pos2 = all_acts[c2]["positive"][layer]
        neg2 = all_acts[c2]["negative"][layer]
        proj = np.concatenate([pos2 @ d1, neg2 @ d1])
        labels = np.array([1]*len(pos2) + [0]*len(neg2))
        acc = max(np.corrcoef(proj, labels)[0, 1], 0)
        entanglement = (cos + acc) / 2
        entanglements.append((c1, c2, entanglement))
    entanglements.sort(key=lambda x: -x[2])
    print("  Top 5 most entangled:")
    for c1, c2, e in entanglements[:5]:
        print(f"    {c1:12s} - {c2:12s}: {e:.4f}")
    print()


def concept_activation_final_layer_summary_1230(all_acts, concept_names):
    """Phase 1230: Summary of activation properties at the final layer."""
    print("=" * 70)
    print("PHASE 1230: FINAL LAYER (L23) ACTIVATION SUMMARY")
    print("=" * 70)
    layer = 23
    for cname in concept_names:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        sep = np.linalg.norm(pos.mean(0) - neg.mean(0))
        pos_norm = np.mean(np.linalg.norm(pos, axis=1))
        neg_norm = np.mean(np.linalg.norm(neg, axis=1))
        print(f"  {cname:20s} | sep: {sep:.3f} | pos_norm: {pos_norm:.1f} | neg_norm: {neg_norm:.1f}")
    print()


def concept_direction_cosine_decay_from_optimal_layer(all_acts, concept_names):
    """Phase 1231: How fast does direction quality decay from optimal layer."""
    print("=" * 70)
    print("PHASE 1231: DIRECTION COSINE DECAY FROM OPTIMAL LAYER")
    print("=" * 70)
    for cname in concept_names[:4]:
        norms = [np.linalg.norm(all_acts[cname]["positive"][l].mean(0) - all_acts[cname]["negative"][l].mean(0)) for l in range(24)]
        best_l = int(np.argmax(norms))
        best_dir = all_acts[cname]["positive"][best_l].mean(0) - all_acts[cname]["negative"][best_l].mean(0)
        best_dir = best_dir / (np.linalg.norm(best_dir) + 1e-10)
        decay = []
        for l in range(24):
            d = all_acts[cname]["positive"][l].mean(0) - all_acts[cname]["negative"][l].mean(0)
            d = d / (np.linalg.norm(d) + 1e-10)
            decay.append(abs(float(best_dir @ d)))
        print(f"  {cname:20s} | best: L{best_l} | L0: {decay[0]:.3f} | L12: {decay[12]:.3f} | L23: {decay[23]:.3f}")
    print()


def concept_neuron_top_pair_joint_synergy(all_acts, concept_names):
    """Phase 1232: Joint information content of top neuron pairs."""
    print("=" * 70)
    print("PHASE 1232: TOP NEURON PAIR JOINT SYNERGY")
    print("=" * 70)
    layer = 10
    for cname in concept_names[:3]:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        diff = np.abs(pos.mean(0) - neg.mean(0))
        top3 = np.argsort(diff)[-3:][::-1]
        combined = np.vstack([pos, neg])
        labels = np.array([1]*len(pos) + [0]*len(neg))
        for i in range(len(top3)):
            for j in range(i+1, len(top3)):
                joint = combined[:, [top3[i], top3[j]]]
                joint_mi = mutual_info_classif(joint, labels, n_neighbors=3, random_state=42).sum()
                ind_mi = mutual_info_classif(combined[:, [top3[i]]], labels, n_neighbors=3, random_state=42)[0]
                ind_mi += mutual_info_classif(combined[:, [top3[j]]], labels, n_neighbors=3, random_state=42)[0]
                synergy = joint_mi - ind_mi
                print(f"  {cname:15s} | n{top3[i]:3d}+n{top3[j]:3d} | joint MI: {joint_mi:.4f} | sum ind: {ind_mi:.4f} | synergy: {synergy:+.4f}")
    print()


def concept_direction_concept_direction_volume_spanned(all_acts, concept_names):
    """Phase 1233: Volume of parallelepiped spanned by concept directions."""
    print("=" * 70)
    print("PHASE 1233: VOLUME SPANNED BY CONCEPT DIRECTIONS")
    print("=" * 70)
    layer = 10
    dirs = []
    for cname in concept_names:
        d = all_acts[cname]["positive"][layer].mean(0) - all_acts[cname]["negative"][layer].mean(0)
        dirs.append(d)
    dir_matrix = np.array(dirs)
    gram = dir_matrix @ dir_matrix.T
    det = np.linalg.det(gram)
    volume = np.sqrt(max(det, 0))
    # Compare to maximum possible (if all orthogonal with same norms)
    norms = np.array([np.linalg.norm(d) for d in dirs])
    max_volume = np.prod(norms)
    print(f"  Gram determinant: {det:.4f}")
    print(f"  Volume: {volume:.4f}")
    print(f"  Max possible volume: {max_volume:.4f}")
    print(f"  Volume ratio: {volume/(max_volume+1e-10):.6f}")
    print()


def concept_activation_layer_wise_norm_statistics(all_acts, concept_names):
    """Phase 1234: Norm statistics at each layer for all concepts combined."""
    print("=" * 70)
    print("PHASE 1234: LAYER-WISE NORM STATISTICS")
    print("=" * 70)
    for l in [0, 4, 8, 12, 16, 20, 23]:
        all_norms = []
        for cname in concept_names:
            combined = np.vstack([all_acts[cname]["positive"][l], all_acts[cname]["negative"][l]])
            all_norms.extend(np.linalg.norm(combined, axis=1).tolist())
        all_norms = np.array(all_norms)
        print(f"  L{l:2d} | mean: {all_norms.mean():.1f} | std: {all_norms.std():.1f} | min: {all_norms.min():.1f} | max: {all_norms.max():.1f}")
    print()


def concept_neuron_concept_exclusive_neurons(all_acts, concept_names):
    """Phase 1235: Find neurons exclusive to single concepts."""
    print("=" * 70)
    print("PHASE 1235: CONCEPT-EXCLUSIVE NEURONS")
    print("=" * 70)
    layer = 10
    n_neurons = all_acts[concept_names[0]]["positive"][layer].shape[1]
    exclusive = {c: [] for c in concept_names}
    for j in range(n_neurons):
        responses = {}
        for cname in concept_names:
            diff = abs(all_acts[cname]["positive"][layer][:, j].mean() - all_acts[cname]["negative"][layer][:, j].mean())
            responses[cname] = diff
        sorted_resp = sorted(responses.values(), reverse=True)
        if sorted_resp[0] > 0.1 and sorted_resp[0] > 3 * sorted_resp[1]:
            best_c = max(responses, key=responses.get)
            exclusive[best_c].append(j)
    for cname in concept_names:
        print(f"  {cname:20s} | exclusive neurons: {len(exclusive[cname])}")
    print()


def concept_direction_concept_direction_effective_rank(all_acts, concept_names):
    """Phase 1236: Effective rank of the concept direction matrix."""
    print("=" * 70)
    print("PHASE 1236: EFFECTIVE RANK OF DIRECTION MATRIX")
    print("=" * 70)
    for l in [0, 6, 12, 18, 23]:
        dirs = []
        for cname in concept_names:
            d = all_acts[cname]["positive"][l].mean(0) - all_acts[cname]["negative"][l].mean(0)
            dirs.append(d)
        dir_matrix = np.array(dirs)
        svals = np.linalg.svd(dir_matrix, compute_uv=False)
        # Effective rank via entropy
        p = svals / (svals.sum() + 1e-10)
        eff_rank = np.exp(-np.sum(p * np.log(p + 1e-10)))
        print(f"  L{l:2d} | eff rank: {eff_rank:.2f} | max/min sval: {svals[0]/(svals[-1]+1e-10):.1f}")
    print()


def concept_activation_concept_activation_cross_layer_projection(all_acts, concept_names):
    """Phase 1237: Project activations from one layer onto another's direction."""
    print("=" * 70)
    print("PHASE 1237: CROSS-LAYER DIRECTION PROJECTION")
    print("=" * 70)
    for cname in concept_names[:3]:
        # Direction at layer 10
        d10 = all_acts[cname]["positive"][10].mean(0) - all_acts[cname]["negative"][10].mean(0)
        d10 = d10 / (np.linalg.norm(d10) + 1e-10)
        # Project layers 0, 5, 15, 23 onto this direction
        for l in [0, 5, 15, 23]:
            pos_proj = all_acts[cname]["positive"][l] @ d10
            neg_proj = all_acts[cname]["negative"][l] @ d10
            sep = abs(pos_proj.mean() - neg_proj.mean())
            print(f"  {cname:15s} | L{l:2d}->L10 dir | sep: {sep:.3f}")
    print()


def concept_neuron_concept_neuron_activation_histogram_overlap(all_acts, concept_names):
    """Phase 1238: Histogram overlap between pos/neg per neuron."""
    print("=" * 70)
    print("PHASE 1238: NEURON ACTIVATION HISTOGRAM OVERLAP")
    print("=" * 70)
    layer = 10
    for cname in concept_names[:3]:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        diff = np.abs(pos.mean(0) - neg.mean(0))
        top3 = np.argsort(diff)[-3:][::-1]
        for n in top3:
            bins = np.linspace(min(pos[:, n].min(), neg[:, n].min()), max(pos[:, n].max(), neg[:, n].max()), 21)
            h_pos, _ = np.histogram(pos[:, n], bins=bins, density=True)
            h_neg, _ = np.histogram(neg[:, n], bins=bins, density=True)
            overlap = np.sum(np.minimum(h_pos, h_neg)) * (bins[1] - bins[0])
            print(f"  {cname:15s} | neuron {n:4d} | histogram overlap: {overlap:.4f}")
    print()


def concept_direction_concept_direction_angle_rank_correlation(all_acts, concept_names):
    """Phase 1239: Rank correlation of pairwise angles across layers."""
    print("=" * 70)
    print("PHASE 1239: ANGLE RANK CORRELATION ACROSS LAYERS")
    print("=" * 70)
    from scipy.stats import spearmanr
    pairs = [(concept_names[i], concept_names[j]) for i in range(len(concept_names)) for j in range(i+1, len(concept_names))]
    layer_a, layer_b = 5, 15
    angles_a = []
    angles_b = []
    for c1, c2 in pairs:
        for l, angles_list in [(layer_a, angles_a), (layer_b, angles_b)]:
            d1 = all_acts[c1]["positive"][l].mean(0) - all_acts[c1]["negative"][l].mean(0)
            d2 = all_acts[c2]["positive"][l].mean(0) - all_acts[c2]["negative"][l].mean(0)
            cos = abs(float(d1 @ d2 / (np.linalg.norm(d1) * np.linalg.norm(d2) + 1e-10)))
            angles_list.append(np.degrees(np.arccos(np.clip(cos, 0, 1))))
    rho, pval = spearmanr(angles_a, angles_b)
    print(f"  L{layer_a} vs L{layer_b} angle rank correlation: rho={rho:.4f} p={pval:.4f}")
    print(f"  (High rho = concept geometry is preserved across layers)")
    print()


def concept_activation_summary_1240(all_acts, concept_names):
    """Phase 1240: Comprehensive analysis summary at 1240 phases."""
    print("=" * 70)
    print("PHASE 1240: COMPREHENSIVE ANALYSIS SUMMARY (1240 PHASES)")
    print("=" * 70)
    layer = 10
    print(f"  Model: Qwen2.5-0.5B | 24 layers | hidden_size=896")
    print(f"  Concepts analyzed: {len(concept_names)}")
    print(f"  Analysis phases completed: 1240")
    # Direction norms
    norms = []
    for cname in concept_names:
        d = all_acts[cname]["positive"][layer].mean(0) - all_acts[cname]["negative"][layer].mean(0)
        norms.append(np.linalg.norm(d))
    print(f"  Mean direction norm (L{layer}): {np.mean(norms):.3f} (range: {min(norms):.3f}-{max(norms):.3f})")
    # Pairwise angles
    dirs = []
    for cname in concept_names:
        d = all_acts[cname]["positive"][layer].mean(0) - all_acts[cname]["negative"][layer].mean(0)
        dirs.append(d / (np.linalg.norm(d) + 1e-10))
    angles = []
    for i in range(len(dirs)):
        for j in range(i+1, len(dirs)):
            angles.append(np.degrees(np.arccos(np.clip(abs(float(dirs[i] @ dirs[j])), 0, 1))))
    print(f"  Mean pairwise angle: {np.mean(angles):.1f}° (min: {min(angles):.1f}°, max: {max(angles):.1f}°)")
    print()


def concept_direction_cosine_between_early_late_layers(all_acts, concept_names):
    """Phase 1241: Compare directions at early layers vs late layers."""
    print("=" * 70)
    print("PHASE 1241: EARLY vs LATE LAYER DIRECTION COSINE")
    print("=" * 70)
    for cname in concept_names:
        d_early = all_acts[cname]["positive"][2].mean(0) - all_acts[cname]["negative"][2].mean(0)
        d_late = all_acts[cname]["positive"][20].mean(0) - all_acts[cname]["negative"][20].mean(0)
        d_early = d_early / (np.linalg.norm(d_early) + 1e-10)
        d_late = d_late / (np.linalg.norm(d_late) + 1e-10)
        cos = float(d_early @ d_late)
        print(f"  {cname:20s} | L2 vs L20 cosine: {cos:.4f} | angle: {np.degrees(np.arccos(np.clip(abs(cos), 0, 1))):.1f}°")
    print()


def concept_neuron_activation_sign_consistency_across_layers(all_acts, concept_names):
    """Phase 1242: Check sign consistency of concept-discriminative neurons."""
    print("=" * 70)
    print("PHASE 1242: NEURON SIGN CONSISTENCY ACROSS LAYERS")
    print("=" * 70)
    for cname in concept_names[:4]:
        # Top neurons at layer 10
        diff10 = all_acts[cname]["positive"][10].mean(0) - all_acts[cname]["negative"][10].mean(0)
        top5 = np.argsort(np.abs(diff10))[-5:]
        consistent = 0
        for n in top5:
            signs = []
            for l in range(24):
                d = all_acts[cname]["positive"][l][:, n].mean() - all_acts[cname]["negative"][l][:, n].mean()
                signs.append(np.sign(d))
            if all(s == signs[0] for s in signs):
                consistent += 1
        print(f"  {cname:20s} | sign-consistent top neurons: {consistent}/5")
    print()


def concept_direction_concept_direction_concept_triplet_volume(all_acts, concept_names):
    """Phase 1243: Volume of triplets of concept directions."""
    print("=" * 70)
    print("PHASE 1243: CONCEPT TRIPLET VOLUMES")
    print("=" * 70)
    layer = 10
    dirs = {}
    for cname in concept_names:
        d = all_acts[cname]["positive"][layer].mean(0) - all_acts[cname]["negative"][layer].mean(0)
        dirs[cname] = d / (np.linalg.norm(d) + 1e-10)
    triplets = [(0, 1, 2), (0, 3, 6), (1, 4, 7), (2, 5, 7)]
    for i, j, k in triplets:
        if i < len(concept_names) and j < len(concept_names) and k < len(concept_names):
            c1, c2, c3 = concept_names[i], concept_names[j], concept_names[k]
            M = np.array([dirs[c1], dirs[c2], dirs[c3]])
            gram = M @ M.T
            vol = np.sqrt(max(np.linalg.det(gram), 0))
            print(f"  {c1:10s}-{c2:10s}-{c3:10s} | volume: {vol:.6f} (max=1)")
    print()


def concept_activation_within_concept_pca_alignment(all_acts, concept_names):
    """Phase 1244: Alignment of within-concept PCA with concept direction."""
    print("=" * 70)
    print("PHASE 1244: WITHIN-CONCEPT PCA vs DIRECTION ALIGNMENT")
    print("=" * 70)
    layer = 10
    for cname in concept_names[:4]:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        combined = np.vstack([pos, neg])
        centered = combined - combined.mean(0)
        cov = np.cov(centered.T)
        eigvals, eigvecs = np.linalg.eigh(cov)
        pc1 = eigvecs[:, -1]  # top PC
        direction = pos.mean(0) - neg.mean(0)
        direction = direction / (np.linalg.norm(direction) + 1e-10)
        align = abs(float(pc1 @ direction))
        print(f"  {cname:20s} | PC1-direction alignment: {align:.4f} | PC1 explains: {eigvals[-1]/eigvals.sum()*100:.1f}%")
    print()


def concept_neuron_concept_neuron_redundancy_analysis(all_acts, concept_names):
    """Phase 1245: Redundancy among top neurons for each concept."""
    print("=" * 70)
    print("PHASE 1245: TOP NEURON REDUNDANCY ANALYSIS")
    print("=" * 70)
    layer = 10
    for cname in concept_names[:4]:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        diff = np.abs(pos.mean(0) - neg.mean(0))
        top10 = np.argsort(diff)[-10:]
        combined = np.vstack([pos, neg])
        sub = combined[:, top10]
        corr = np.corrcoef(sub.T)
        np.fill_diagonal(corr, 0)
        mean_corr = np.abs(corr).mean()
        max_corr = np.abs(corr).max()
        print(f"  {cname:20s} | top10 mean |corr|: {mean_corr:.4f} | max: {max_corr:.4f} | {'redundant' if mean_corr > 0.3 else 'independent'}")
    print()


def concept_direction_concept_direction_direction_norm_ratio_across_layers(all_acts, concept_names):
    """Phase 1246: Ratio of largest to smallest concept direction norm at each layer."""
    print("=" * 70)
    print("PHASE 1246: DIRECTION NORM RATIO ACROSS LAYERS")
    print("=" * 70)
    for l in [0, 6, 12, 18, 23]:
        norms = []
        for cname in concept_names:
            d = all_acts[cname]["positive"][l].mean(0) - all_acts[cname]["negative"][l].mean(0)
            norms.append(np.linalg.norm(d))
        ratio = max(norms) / (min(norms) + 1e-10)
        strongest = concept_names[int(np.argmax(norms))]
        weakest = concept_names[int(np.argmin(norms))]
        print(f"  L{l:2d} | ratio: {ratio:.2f} | strongest: {strongest} ({max(norms):.2f}) | weakest: {weakest} ({min(norms):.2f})")
    print()


def concept_activation_concept_activation_fisher_ratio_per_layer(all_acts, concept_names):
    """Phase 1247: Fisher discriminant ratio per layer."""
    print("=" * 70)
    print("PHASE 1247: FISHER RATIO PER LAYER")
    print("=" * 70)
    for cname in concept_names[:4]:
        ratios = []
        for l in range(24):
            pos = all_acts[cname]["positive"][l]
            neg = all_acts[cname]["negative"][l]
            diff = pos.mean(0) - neg.mean(0)
            pooled = 0.5 * (np.var(pos, axis=0) + np.var(neg, axis=0)) + 1e-10
            fdr = np.sum(diff ** 2 / pooled)
            ratios.append(fdr)
        best_l = int(np.argmax(ratios))
        print(f"  {cname:20s} | best: L{best_l} (FDR={ratios[best_l]:.0f}) | L0: {ratios[0]:.0f} | L23: {ratios[23]:.0f}")
    print()


def concept_neuron_concept_neuron_activation_spread_index(all_acts, concept_names):
    """Phase 1248: Spread of activations across neuron populations."""
    print("=" * 70)
    print("PHASE 1248: NEURON ACTIVATION SPREAD INDEX")
    print("=" * 70)
    layer = 10
    for cname in concept_names[:4]:
        pos = all_acts[cname]["positive"][layer]
        neg = all_acts[cname]["negative"][layer]
        combined = np.vstack([pos, neg])
        # Spread: ratio of variance in top 10% neurons to bottom 90%
        var_per_neuron = np.var(combined, axis=0)
        sorted_var = np.sort(var_per_neuron)[::-1]
        top10_var = sorted_var[:len(sorted_var)//10].mean()
        bot90_var = sorted_var[len(sorted_var)//10:].mean()
        print(f"  {cname:20s} | top10% var: {top10_var:.4f} | bot90% var: {bot90_var:.4f} | ratio: {top10_var/(bot90_var+1e-10):.2f}")
    print()


def concept_direction_concept_direction_cosine_similarity_stability(all_acts, concept_names):
    """Phase 1249: Stability of cosine similarity matrix across layers."""
    print("=" * 70)
    print("PHASE 1249: COSINE SIMILARITY MATRIX STABILITY")
    print("=" * 70)
    from scipy.stats import spearmanr
    cos_matrices = {}
    for l in [5, 10, 15, 20]:
        dirs = []
        for cname in concept_names:
            d = all_acts[cname]["positive"][l].mean(0) - all_acts[cname]["negative"][l].mean(0)
            dirs.append(d / (np.linalg.norm(d) + 1e-10))
        n = len(dirs)
        flat = []
        for i in range(n):
            for j in range(i+1, n):
                flat.append(abs(float(dirs[i] @ dirs[j])))
        cos_matrices[l] = flat
    for la, lb in [(5, 10), (10, 15), (15, 20), (5, 20)]:
        rho, _ = spearmanr(cos_matrices[la], cos_matrices[lb])
        print(f"  L{la} vs L{lb} | rank corr: {rho:.4f}")
    print()


