    print("=" * 70)
    layer = 10
    top_sets = {}
    for cname in concept_names:
        d = np.abs(all_acts[cname]["positive"][layer].mean(0) - all_acts[cname]["negative"][layer].mean(0))
        top_sets[cname] = set(np.argsort(d)[-20:])
