    print(f"  Ratio λ1/λn: {eigvals[0]/(eigvals[-1]+1e-10):.2f}")
    print(f"  Participation ratio: {(eigvals.sum()**2)/(np.sum(eigvals**2)+1e-10):.2f}")
    print()


