    from scipy.stats import spearmanr
    layer = 10
    importances = {}
    for cname in concept_names:
        d = np.abs(np.mean(all_acts[cname]["positive"][layer], axis=0) -
                   np.mean(all_acts[cname]["negative"][layer], axis=0))
