        max_l = int(np.argmax(angular_vel))
        print(f"  {cname}: max angular velocity at L{max_l}→L{max_l+1} "
              f"({angular_vel[max_l]:.2f}°/layer), mean={np.mean(angular_vel):.2f}°/layer")
