        norms_by_layer = []
        for l in range(24):
            pos = all_acts[cname]["positive"][l]
            neg = all_acts[cname]["negative"][l]
            all_data = np.vstack([pos, neg])
            norms = np.linalg.norm(all_data, axis=1)
            norms_by_layer.append(np.mean(norms))
